  ('two-sum-sorted', 'go', 'solution.go', 'package main
func twoSum(numbers []int, target int) []int {
	lo, hi := 0, len(numbers)-1
	for lo < hi {
		sum := numbers[lo] + numbers[hi]
		switch {
		case sum == target:
			return []int{lo + 1, hi + 1}
		case sum < target:
			lo++
		default:
			hi--
		}
	}
	return nil
}
', true, 0),
  ('max-subarray-sum-k', 'go', 'solution.go', 'package main
func maxSubarraySumK(values []int, k int) int {
	sum := 0
	for i := 0; i < k; i++ {
		sum += values[i]
	}
	best := sum
	for right := k; right < len(values); right++ {
		sum += values[right] - values[right-k]
		if sum > best {
			best = sum
		}
	}
	return best
}
', true, 0),
  ('longest-substring', 'go', 'solution.go', 'package main
func lengthOfLongestSubstring(s string) int {
	seen := make(map[byte]int)
	best, left := 0, 0
	for right := 0; right < len(s); right++ {
		c := s[right]
		if i, ok := seen[c]; ok && i >= left {
			left = i + 1
		}
		seen[c] = right
		if right-left+1 > best {
			best = right - left + 1
		}
	}
	return best
}
