  ('bubble-sort', 'python', 'solution.py', '# Bubble Sort
# Time: O(n^2) worst/avg, O(n) best | Space: O(1)

def bubble_sort(nums: list[int]) -> None:
    n = len(nums)
    for i in range(n - 1):
        swapped = False
        for j in range(n - 1 - i):
            if nums[j] > nums[j + 1]:
                nums[j], nums[j + 1] = nums[j + 1], nums[j]
                swapped = True
        if not swapped:
            break
