  ('bubble-sort', 'typescript', 'solution.ts', '// Bubble Sort
// Time: O(n^2) worst/avg, O(n) best | Space: O(1)

function bubbleSort(nums: number[]): void {
  const n = nums.length;
  for (let i = 0; i < n - 1; i++) {
    let swapped = false;
    for (let j = 0; j < n - 1 - i; j++) {
      if (nums[j] > nums[j + 1]) {
        [nums[j], nums[j + 1]] = [nums[j + 1], nums[j]];
        swapped = true;
      }
    }
    if (!swapped) break;
  }
}
