func mergeSort(nums []int) {
	n := len(nums)
	buf := make([]int, n)
	for width := 1; width < n; width *= 2 {
		for lo := 0; lo+width < n; lo += 2 * width {
			mid := lo + width - 1
			hi := lo + 2*width - 1
			if hi > n-1 {
				hi = n - 1
			}
			i, j, k := lo, mid+1, lo
			for i <= mid && j <= hi {
				if nums[i] <= nums[j] {
					buf[k] = nums[i]
					i++
				} else {
					buf[k] = nums[j]
					j++
				}
				k++
			}
			for i <= mid {
				buf[k] = nums[i]
				i++
				k++
			}
			for j <= hi {
				buf[k] = nums[j]
				j++
				k++
			}
			copy(nums[lo:hi+1], buf[lo:hi+1])
		}
	}
}
