def bfs(n, edges, start):
    if start < 1 or start > n:
        return [-1] * (n - 1)
    adj = [[] for _ in range(n + 1)]
    for a, b in edges:
        adj[a].append(b)
        adj[b].append(a)
    dist = [-1] * (n + 1)
    dist[start] = 0
    q = deque([start])
    while q:
        cur = q.popleft()
        for nb in adj[cur]:
            if dist[nb] == -1:
                dist[nb] = dist[cur] + 6
                q.append(nb)
    return [dist[i] for i in range(1, n + 1) if i != start]
