class Solution {
    int[] bfs(int n, int[][] edges, int start) {
        if (start < 1 || start > n) {
            int[] res = new int[n - 1];
            Arrays.fill(res, -1);
            return res;
        }
        List<List<Integer>> adj = new ArrayList<>();
        for (int i = 0; i <= n; i++) adj.add(new ArrayList<>());
        for (int[] e : edges) {
            adj.get(e[0]).add(e[1]);
            adj.get(e[1]).add(e[0]);
        }
        int[] dist = new int[n + 1];
        Arrays.fill(dist, -1);
        dist[start] = 0;
        Deque<Integer> q = new ArrayDeque<>();
        q.add(start);
        while (!q.isEmpty()) {
            int cur = q.poll();
            for (int nb : adj.get(cur)) {
                if (dist[nb] == -1) {
                    dist[nb] = dist[cur] + 6;
                    q.add(nb);
                }
            }
        }
        int[] res = new int[n - 1];
        int k = 0;
        for (int i = 1; i <= n; i++) {
            if (i != start) res[k++] = dist[i];
        }
        return res;
    }
}
