func findShortestPathWithBfs(adj [][]int, src, dest int) []int {
	n := len(adj)
	dist := make([]int, n)
	pred := make([]int, n)
	for i := range dist {
		dist[i] = -1
		pred[i] = -1
	}
	q := []int{src}
	dist[src] = 0
	for len(q) > 0 {
		v := q[0]
		q = q[1:]
		if v == dest {
			break
		}
		for _, nb := range adj[v] {
			if dist[nb] == -1 {
				dist[nb] = dist[v] + 1
				pred[nb] = v
				q = append(q, nb)
			}
		}
	}
	if dist[dest] == -1 {
		return nil
	}
	var path []int
	for at := dest; at != -1; at = pred[at] {
		path = append([]int{at}, path...)
	}
	return path
}
