func graphTraversalBFS(src *GraphNode) []int {
	if src == nil {
		return nil
	}
	visited := map[*GraphNode]bool{src: true}
	q := []*GraphNode{src}
	var order []int
	for len(q) > 0 {
		v := q[0]
		q = q[1:]
		order = append(order, v.Label)
		for _, nb := range v.Neighbors {
			if !visited[nb] {
				visited[nb] = true
				q = append(q, nb)
			}
		}
	}
	return order
}

func btGraphDfs(n *GraphNode, visited map[*GraphNode]bool, order *[]int) {
	if n == nil || visited[n] {
		return
	}
	visited[n] = true
	*order = append(*order, n.Label)
	for _, nb := range n.Neighbors {
		btGraphDfs(nb, visited, order)
	}
}
