class Solution {
    boolean hasPath(int[][] adj, int src, int dest) {
        if (src == dest) return true;
        boolean[] visited = new boolean[adj.length];
        Deque<Integer> q = new ArrayDeque<>();
        q.add(src);
        visited[src] = true;
        while (!q.isEmpty()) {
