func printAllPathsFromSourceToDestin(adj [][]int, src, dest int) [][]int {
	var res [][]int
	path := []int{src}
	visited := make([]bool, len(adj))
	visited[src] = true
	btPrintPaths(adj, src, dest, visited, &path, &res)
	return res
}

func btPrintPaths(adj [][]int, v, dest int, visited []bool, path *[]int, res *[][]int) {
	if v == dest {
		cp := append([]int(nil), *path...)
		*res = append(*res, cp)
		return
	}
	for _, nb := range adj[v] {
		if !visited[nb] {
			visited[nb] = true
			*path = append(*path, nb)
			btPrintPaths(adj, nb, dest, visited, path, res)
			*path = (*path)[:len(*path)-1]
			visited[nb] = false
		}
	}
}
