  ('imp-1-subset-component', 'go', 'solution.go', 'package main

import (
	"math/bits"
)

type bitDSU [64]uint8

func findConnectedComponents(d []uint64) int64 {
	var active []uint64
	for _, v := range d {
		if bits.OnesCount64(v) >= 2 {
			active = append(active, v)
		}
	}
	inactive := len(d) - len(active)

	var baseDSU bitDSU
	for i := 0; i < 64; i++ {
		baseDSU[i] = uint8(i)
	}

	var total int64
	subsetComponentDfs(active, 0, baseDSU, 64, &total)
	return total << inactive
}

func bitDSUFind(dsu *bitDSU, x uint8) uint8 {
	for dsu[x] != x {
		x = dsu[x]
	}
	return x
}

func subsetComponentDfs(active []uint64, idx int, dsu bitDSU, cnt int, total *int64) {
	if idx == len(active) {
		*total += int64(cnt)
		return
	}
	subsetComponentDfs(active, idx+1, dsu, cnt, total)

	next := dsu
	nc := cnt
	v := active[idx]
	first := -1
	for v > 0 {
		b := bits.TrailingZeros64(v)
		if first == -1 {
			first = b
		} else {
			ra, rb := bitDSUFind(&next, uint8(first)), bitDSUFind(&next, uint8(b))
			if ra != rb {
				next[ra] = rb
				nc--
			}
		}
		v &= v - 1
	}
	subsetComponentDfs(active, idx+1, next, nc, total)
}
