func removeInvalidParentheses(s string) string {
	bad := make([]bool, len(s))
	var stack []int
	for i := 0; i < len(s); i++ {
		c := s[i]
		if c == ''('' {
			stack = append(stack, i)
		} else if c == '')'' {
			if len(stack) == 0 {
				bad[i] = true
			} else {
				stack = stack[:len(stack)-1]
			}
		}
	}
	for _, idx := range stack {
		bad[idx] = true
	}
	out := make([]byte, 0, len(s))
	for i := 0; i < len(s); i++ {
		if !bad[i] {
			out = append(out, s[i])
		}
	}
	return string(out)
}
