            for j in range(len(cur)):
                if cur[j] != ''('' and cur[j] != '')'':
                    continue
                nxt = cur[:j] + cur[j + 1:]
                if nxt not in vis:
                    vis.add(nxt)
                    q.append(nxt)
    return res


def is_valid(s: str) -> bool:
    cnt = 0
    for ch in s:
        if ch == ''('':
            cnt += 1
        elif ch == '')'':
            cnt -= 1
        if cnt < 0:
