  ('imp-4-floyd-city-of-blinding-lights', 'go', 'solution.go', 'package main

const INF = 1 << 30

func floydWarshall(n int, edges [][]int, queries [][]int) []int {
	dist := make([][]int, n+1)
	for i := range dist {
		dist[i] = make([]int, n+1)
		for j := range dist[i] {
			dist[i][j] = INF
		}
		dist[i][i] = 0
	}
	for _, e := range edges {
		u, v, w := e[0], e[1], e[2]
		dist[u][v] = w
	}
	for k := 1; k <= n; k++ {
