type WEdge struct {
	Next   int
	Weight int
}

func findShortestPathWithDijkstras(adj [][]WEdge, src int) []int {
	n := len(adj)
	dist := make([]int, n)
	used := make([]bool, n)
	for i := range dist {
		dist[i] = int(^uint(0) >> 1)
	}
	dist[src] = 0
	for count := 0; count < n; count++ {
		u := -1
		best := int(^uint(0) >> 1)
		for v := 0; v < n; v++ {
			if !used[v] && dist[v] < best {
				best = dist[v]
				u = v
			}
		}
		if u == -1 {
			break
		}
		used[u] = true
		for _, e := range adj[u] {
			if nd := dist[u] + e.Weight; nd < dist[e.Next] {
				dist[e.Next] = nd
			}
		}
	}
	return dist
}
