class DSU:
    def __init__(self, n):
        self.parent = list(range(n + 1))
        self.size = [1] * (n + 1)

    def find(self, x):
        if self.parent[x] != x:
            self.parent[x] = self.find(self.parent[x])
        return self.parent[x]

    def union(self, x, y):
        rx, ry = self.find(x), self.find(y)
        if rx == ry:
            return
        if self.size[rx] < self.size[ry]:
            rx, ry = ry, rx
        self.parent[ry] = rx
        self.size[rx] += self.size[ry]

    def size_of(self, x):
        return self.size[self.find(x)]


def solve_merging_communities(r, w):
    tokens = r.read().split()
    it = iter(tokens)
    try:
        n = int(next(it))
        q = int(next(it))
    except StopIteration:
        return
    dsu = DSU(n)
    for _ in range(q):
        try:
            op = next(it)
        except StopIteration:
            return
        if op == "M":
            u = int(next(it))
            v = int(next(it))
            dsu.union(u, v)
        elif op == "Q":
            u = int(next(it))
            w.write(str(dsu.size_of(u)) + "\n")', false, 1),
  ('imp-8-merging-communities', 'java', 'Solution.java', 'import java.io.Reader;
import java.io.Writer;
import java.io.IOException;
import java.io.BufferedReader;
import java.io.StreamTokenizer;

class Solution {

    static class DSU {
        int[] parent;
        int[] size;

        DSU(int n) {
            parent = new int[n + 1];
            size = new int[n + 1];
            for (int i = 0; i <= n; i++) {
                parent[i] = i;
                size[i] = 1;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        void union(int x, int y) {
            int rx = find(x), ry = find(y);
            if (rx == ry) {
                return;
            }
            if (size[rx] < size[ry]) {
                int t = rx; rx = ry; ry = t;
            }
            parent[ry] = rx;
            size[rx] += size[ry];
        }

        int sizeOf(int x) {
            return size[find(x)];
        }
    }

    static void solveMergingCommunities(Reader r, Writer w) throws IOException {
        StreamTokenizer in = new StreamTokenizer(new BufferedReader(r));
        in.ordinaryChars(0, 255);
        in.wordChars(''A'', ''Z'');
        in.wordChars(''a'', ''z'');
        in.whitespaceChars(0, '' '');
        in.parseNumbers();

        if (in.nextToken() == StreamTokenizer.TT_EOF) return;
        int n = (int) in.nval;
        if (in.nextToken() == StreamTokenizer.TT_EOF) return;
        int q = (int) in.nval;

        DSU dsu = new DSU(n);
        for (int i = 0; i < q; i++) {
            if (in.nextToken() == StreamTokenizer.TT_EOF) return;
            String op = in.sval;
            if ("M".equals(op)) {
                in.nextToken();
                int u = (int) in.nval;
                in.nextToken();
                int v = (int) in.nval;
                dsu.union(u, v);
            } else if ("Q".equals(op)) {
                in.nextToken();
                int u = (int) in.nval;
                w.write(Integer.toString(dsu.sizeOf(u)));
                w.write("\n");
            }
        }
        w.flush();
    }
}', false, 2),
