    public int numSimilarGroups(String[] strs) {
        int n = strs.length;
        int[] parent = new int[n];
        int[] size = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            size[i] = 1;
        }
        int[] groups = {n};
        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                int diffs = 0;
                for (int k = 0; k < strs[i].length(); k++) {
                    if (strs[i].charAt(k) != strs[j].charAt(k)) {
                        diffs++;
                        if (diffs > 2) {
                            break;
                        }
                    }
                }
                if (diffs == 0 || diffs == 2) {
                    similarGroupsUnion(parent, size, groups, i, j);
                }
            }
        }
        return groups[0];
    }

    private int similarGroupsFind(int[] parent, int x) {
        if (parent[x] != x) {
            parent[x] = similarGroupsFind(parent, parent[x]);
        }
        return parent[x];
    }

    private void similarGroupsUnion(int[] parent, int[] size, int[] groups, int x, int y) {
        int rx = similarGroupsFind(parent, x);
        int ry = similarGroupsFind(parent, y);
        if (rx == ry) {
            return;
        }
        if (size[rx] < size[ry]) {
            int tmp = rx;
            rx = ry;
            ry = tmp;
        }
        parent[ry] = rx;
        size[rx] += size[ry];
        groups[0]--;
    }
