from typing import List


def ladder_length(begin_word: str, end_word: str, word_list: List[str]) -> int:
    word_set = set(word_list)
    if end_word not in word_set:
        return 0
    q = deque([begin_word])
    steps = 0
    while q:
        steps += 1
        for _ in range(len(q)):
            cur = q.popleft()
