func shortestPath(grid [][]int, k int) int {
	m, n := len(grid), len(grid[0])
	if m == 1 && n == 1 {
		return 0
	}
	if k >= m+n-3 {
		return m + n - 2
	}
	vis := make([][][]bool, m)
	for i := range vis {
		vis[i] = make([][]bool, n)
		for j := range vis[i] {
			vis[i][j] = make([]bool, k+1)
		}
	}
	q := [][3]int{{0, 0, k}}
	vis[0][0][k] = true
	dirs := [4][2]int{{0, 1}, {0, -1}, {1, 0}, {-1, 0}}
	steps := 0
	for len(q) > 0 {
		steps++
		sz := len(q)
		for i := 0; i < sz; i++ {
			cur := q[0]
			q = q[1:]
			r, c, rem := cur[0], cur[1], cur[2]
			for _, d := range dirs {
				nr, nc := r+d[0], c+d[1]
				if nr < 0 || nr >= m || nc < 0 || nc >= n {
					continue
				}
				nextRem := rem - grid[nr][nc]
				if nextRem < 0 || vis[nr][nc][nextRem] {
					continue
				}
				if nr == m-1 && nc == n-1 {
					return steps
				}
				vis[nr][nc][nextRem] = true
				q = append(q, [3]int{nr, nc, nextRem})
			}
		}
	}
	return -1
}
