func cleanRoom(robot Robot) {
	dirs := [4][2]int{{-1, 0}, {0, 1}, {1, 0}, {0, -1}}
	vis := map[[2]int]bool{}
	btCleanRoom(robot, dirs, vis, 0, 0, 0)
