func btCleanRoom(robot Robot, dirs [4][2]int, vis map[[2]int]bool, r, c, d int) {
	vis[[2]int{r, c}] = true
	robot.Clean()
	for i := 0; i < 4; i++ {
		nd := (d + i) % 4
		nr, nc := r+dirs[nd][0], c+dirs[nd][1]
		if !vis[[2]int{nr, nc}] && robot.Move() {
