  ('imp-13-robot-room-cleaner', 'java', 'Solution.java', 'import java.util.HashSet;
import java.util.Set;

class Solution {

    interface Robot {
        boolean move();
        void turnLeft();
        void turnRight();
        void clean();
    }

    static final int[][] DIRS = {{-1, 0}, {0, 1}, {1, 0}, {0, -1}};

    public void cleanRoom(Robot robot) {
        Set<Long> vis = new HashSet<>();
        btCleanRoom(robot, vis, 0, 0, 0);
    }

    private void btCleanRoom(Robot robot, Set<Long> vis, int r, int c, int d) {
        vis.add(encode(r, c));
        robot.clean();
        for (int i = 0; i < 4; i++) {
            int nd = (d + i) % 4;
            int nr = r + DIRS[nd][0];
            int nc = c + DIRS[nd][1];
            if (!vis.contains(encode(nr, nc)) && robot.move()) {
                btCleanRoom(robot, vis, nr, nc, nd);
                robot.turnRight();
                robot.turnRight();
                robot.move();
                robot.turnRight();
                robot.turnRight();
            }
            robot.turnRight();
        }
    }

    private long encode(int r, int c) {
        return (((long) r) << 32) ^ (c & 0xFFFFFFFFL);
    }
}', false, 2),
  ('imp-14-the-earliest-moment-when-everyone-become-friends', 'go', 'solution.go', 'package main

import "sort"

type logsByTimestamp struct {
	logs [][]int
}

func (l logsByTimestamp) Len() int { return len(l.logs) }
func (l logsByTimestamp) Less(i, j int) bool {
	return l.logs[i][0] < l.logs[j][0]
}
func (l logsByTimestamp) Swap(i, j int) { l.logs[i], l.logs[j] = l.logs[j], l.logs[i] }

func earliestAcq(logs [][]int, n int) int {
	sort.Sort(logsByTimestamp{logs: logs})
	parent := make([]int, n)
	size := make([]int, n)
	for i := range parent {
		parent[i] = i
		size[i] = 1
	}
	groups := n
	for _, l := range logs {
		earliestAcqUnion(parent, size, &groups, l[1], l[2])
		if groups == 1 {
			return l[0]
		}
	}
	return -1
}

func earliestAcqFind(parent []int, x int) int {
	if parent[x] != x {
		parent[x] = earliestAcqFind(parent, parent[x])
	}
	return parent[x]
}

func earliestAcqUnion(parent, size []int, groups *int, x, y int) {
	rx, ry := earliestAcqFind(parent, x), earliestAcqFind(parent, y)
	if rx == ry {
		return
	}
	if size[rx] < size[ry] {
		rx, ry = ry, rx
	}
	parent[ry] = rx
	size[rx] += size[ry]
	*groups--
}
