def earliest_acq(logs: List[List[int]], n: int) -> int:
    logs = sorted(logs, key=lambda l: l[0])
    parent = list(range(n))
    size = [1] * n
    groups = n

    def find(x: int) -> int:
        if parent[x] != x:
            parent[x] = find(parent[x])
        return parent[x]

    def union(x: int, y: int) -> None:
        nonlocal groups
        rx, ry = find(x), find(y)
        if rx == ry:
            return
        if size[rx] < size[ry]:
            rx, ry = ry, rx
        parent[ry] = rx
        size[rx] += size[ry]
        groups -= 1

    for l in logs:
        union(l[1], l[2])
        if groups == 1:
            return l[0]
    return -1', false, 1),
  ('imp-14-the-earliest-moment-when-everyone-become-friends', 'java', 'Solution.java', 'import java.util.Arrays;
import java.util.Comparator;

class Solution {

    private int[] parent;
    private int[] size;
    private int groups;

    public int earliestAcq(int[][] logs, int n) {
        Arrays.sort(logs, Comparator.comparingInt(l -> l[0]));
        parent = new int[n];
        size = new int[n];
        for (int i = 0; i < n; i++) {
            parent[i] = i;
            size[i] = 1;
        }
        groups = n;
        for (int[] l : logs) {
            union(l[1], l[2]);
            if (groups == 1) {
                return l[0];
            }
        }
        return -1;
    }

    private int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    private void union(int x, int y) {
        int rx = find(x), ry = find(y);
        if (rx == ry) {
            return;
        }
        if (size[rx] < size[ry]) {
            int t = rx;
            rx = ry;
            ry = t;
        }
        parent[ry] = rx;
        size[rx] += size[ry];
        groups--;
    }
}', false, 2),
