def number_of_good_paths(vals: List[int], edges: List[List[int]]) -> int:
    n = len(vals)
    parent = list(range(n))
    adj: List[List[int]] = [[] for _ in range(n)]
    for e in edges:
        adj[e[0]].append(e[1])
        adj[e[1]].append(e[0])

    ids = sorted(range(n), key=lambda i: vals[i])

    res = n
    i = 0
    while i < n:
        j = i
        while j < n and vals[ids[j]] == vals[ids[i]]:
            j += 1
        for k in range(i, j):
            u = ids[k]
            for v in adj[u]:
                if vals[v] <= vals[u]:
                    _union(parent, vals, u, v)
        cnt = {}
        for k in range(i, j):
            r = _find(parent, ids[k])
            cnt[r] = cnt.get(r, 0) + 1
        for c in cnt.values():
            res += c * (c - 1) // 2
        i = j
    return res


def _find(parent: List[int], x: int) -> int:
    if parent[x] != x:
        parent[x] = _find(parent, parent[x])
    return parent[x]


def _union(parent: List[int], vals: List[int], x: int, y: int) -> None:
    rx, ry = _find(parent, x), _find(parent, y)
    if rx != ry:
        if vals[rx] < vals[ry]:
