func coursesOrderTopoDFS(numCourses int, prerequisites [][]int) []int {
	adj := make([][]int, numCourses)
	for _, p := range prerequisites {
		adj[p[1]] = append(adj[p[1]], p[0])
	}
	state := make([]int, numCourses)
	var order []int
	for i := 0; i < numCourses; i++ {
		if state[i] == 0 && !btCoursesTopo(adj, i, state, &order) {
			return nil
		}
	}
	for i, j := 0, len(order)-1; i < j; i, j = i+1, j-1 {
		order[i], order[j] = order[j], order[i]
	}
	return order
}

func btCoursesTopo(adj [][]int, v int, state []int, order *[]int) bool {
	if state[v] == 1 {
		return false
	}
	if state[v] == 2 {
		return true
	}
	state[v] = 1
	for _, nb := range adj[v] {
		if !btCoursesTopo(adj, nb, state, order) {
			return false
		}
	}
	state[v] = 2
	*order = append(*order, v)
	return true
}
