	for i := range adj {
		if !visited[i] && btDetectCycleUndirectedDfs(adj, visited, i, -1) {
			return true
		}
	}
	return false
}

func detectCycleDirected(adj [][]int) bool {
	state := make([]int, len(adj))
	for i := range adj {
		if state[i] == 0 && btDetectCycleDirectedDfs(adj, state, i) {
			return true
		}
	}
	return false
}

func btDetectCycleUndirectedDfs(adj [][]int, visited []bool, v, parent int) bool {
	visited[v] = true
	for _, nb := range adj[v] {
		if !visited[nb] {
			if btDetectCycleUndirectedDfs(adj, visited, nb, v) {
				return true
			}
		} else if nb != parent {
			return true
		}
	}
	return false
}

func btDetectCycleDirectedDfs(adj [][]int, state []int, v int) bool {
	state[v] = 1
	for _, nb := range adj[v] {
		if state[nb] == 1 {
			return true
		}
		if state[nb] == 0 && btDetectCycleDirectedDfs(adj, state, nb) {
			return true
		}
	}
	state[v] = 2
	return false
}
