  ('imp-25-critical-connections-in-a-network', 'java', 'Solution.java', 'import java.util.ArrayList;
import java.util.List;

class Solution {

    private int[] disc;
    private int[] low;
    private int timer;
    private List<List<Integer>> res;
    private List<List<Integer>> adj;

    public List<List<Integer>> criticalConnections(int n, List<List<Integer>> connections) {
        adj = new ArrayList<>();
        for (int i = 0; i < n; i++) adj.add(new ArrayList<>());
        for (List<Integer> c : connections) {
            adj.get(c.get(0)).add(c.get(1));
            adj.get(c.get(1)).add(c.get(0));
        }
        disc = new int[n];
        low = new int[n];
        for (int i = 0; i < n; i++) disc[i] = -1;
        timer = 0;
        res = new ArrayList<>();
        btTarjan(0, -1);
        return res;
    }

    private void btTarjan(int u, int parent) {
        disc[u] = timer;
        low[u] = timer;
        timer++;
        for (int v : adj.get(u)) {
            if (v == parent) continue;
            if (disc[v] == -1) {
                btTarjan(v, u);
                if (low[v] < low[u]) low[u] = low[v];
                if (low[v] > disc[u]) {
                    List<Integer> edge = new ArrayList<>();
                    edge.add(u);
                    edge.add(v);
                    res.add(edge);
                }
            } else if (disc[v] < low[u]) {
                low[u] = disc[v];
            }
        }
    }
