func btCombSum(a []int, idx, target int, path []int, res *[][]int) {
	if target < 0 {
		return
	}
	if target == 0 {
		row := make([]int, len(path))
		copy(row, path)
		*res = append(*res, row)
		return
	}
	for i := idx; i < len(a) && target >= a[i]; i++ {
		if i > idx && a[i] == a[i-1] {
			continue
		}
		btCombSum(a, i+1, target-a[i], append(path, a[i]), res)
	}
}
