import "strconv"

func addOperators(num string, target int) []string {
	var res []string
	btAddOperators(num, target, 0, "", 0, 0, &res)
	return res
}

func btAddOperators(num string, target, idx int, path string, eval, prev int, res *[]string) {
	if idx == len(num) {
		if eval == target {
			*res = append(*res, path)
		}
		return
	}
	for i := idx; i < len(num); i++ {
		if i > idx && num[idx] == ''0'' {
			break
		}
		sub := num[idx : i+1]
		val, _ := strconv.Atoi(sub)
		if idx == 0 {
			btAddOperators(num, target, i+1, sub, val, val, res)
		} else {
			btAddOperators(num, target, i+1, path+"+"+sub, eval+val, val, res)
			btAddOperators(num, target, i+1, path+"-"+sub, eval-val, -val, res)
			btAddOperators(num, target, i+1, path+"*"+sub, eval-prev+prev*val, prev*val, res)
		}
	}
}
