func genStroboNums(n int) []string {
	res := make([]string, 0)
	if n == 0 {
		return res
	}
	path := make([]byte, n)
	btStrobo(path, 0, n-1, &res)
	return res
}

func btStrobo(path []byte, low, high int, res *[]string) {
	if low > high {
		*res = append(*res, string(path))
		return
	}
	if low == high {
		for _, c := range []byte{''0'', ''1'', ''8''} {
			path[low] = c
			*res = append(*res, string(path))
		}
		return
	}
