func maxLength(arr []string) int {
	var masks []uint
	for _, s := range arr {
		mask := uint(0)
		dup := false
		for i := 0; i < len(s); i++ {
			bit := uint(1) << (s[i] - ''a'')
			if mask&bit > 0 {
				dup = true
				break
			}
			mask |= bit
		}
		if !dup {
			masks = append(masks, mask)
		}
	}
	res := 0
	btMaxLength(masks, 0, 0, &res)
	return res
}

func btMaxLength(masks []uint, idx int, path uint, res *int) {
	cnt := bits.OnesCount(path)
	if cnt > *res {
		*res = cnt
	}
	for i := idx; i < len(masks); i++ {
		if path&masks[i] == 0 {
			btMaxLength(masks, i+1, path|masks[i], res)
		}
	}
