func operatorCombinations(tokens []int) []int {
	memo := make(map[string][]int)
	return btOps(tokens, memo)
}

func btOps(t []int, memo map[string][]int) []int {
	key := btIntsKey(t)
	if v, ok := memo[key]; ok {
		return v
	}
	if len(t) == 1 {
		return []int{t[0]}
	}
	res := make([]int, 0)
	for i := 1; i < len(t); i++ {
		left := btOps(t[:i], memo)
		right := btOps(t[i:], memo)
		for _, a := range left {
			for _, b := range right {
				res = append(res, a+b, a-b, a*b)
				if b != 0 {
					res = append(res, a/b)
				}
			}
		}
	}
	memo[key] = res
	return res
}

func btIntsKey(a []int) string {
	key := ""
	for i, v := range a {
		if i > 0 {
			key += ","
		}
		key += btIntToString(v)
	}
	return key
}

func btIntToString(n int) string {
	if n == 0 {
		return "0"
	}
	neg := n < 0
	if neg {
		n = -n
	}
	digits := make([]byte, 0)
	for n > 0 {
		digits = append([]byte{byte(''0'' + n%10)}, digits...)
		n /= 10
	}
	if neg {
		return "-" + string(digits)
	}
	return string(digits)
}
