func btPerm(a []int, idx int, res *[][]int) {
	if idx == len(a) {
		row := make([]int, len(a))
		copy(row, a)
		*res = append(*res, row)
		return
	}
	for i := idx; i < len(a); i++ {
		a[idx], a[i] = a[i], a[idx]
		btPerm(a, idx+1, res)
		a[idx], a[i] = a[i], a[idx]
	}
}
