  ('imp-42-cartesian-product-of-multiple-arrays', 'go', 'solution.go', 'package main

func permMultipleArrays(lists [][]string) [][]string {
	res := make([][]string, 0)
	seen := make(map[string]bool)
	btPermLists(lists, []string{}, &res, seen)
	return res
}

func btPermLists(lists [][]string, path []string, res *[][]string, seen map[string]bool) {
	if len(lists) == 0 {
		key := btJoinStrings(path, ",")
		if seen[key] {
			return
		}
		seen[key] = true
		row := make([]string, len(path))
		copy(row, path)
		*res = append(*res, row)
		return
	}
	for _, s := range lists[0] {
		btPermLists(lists[1:], append(path, s), res, seen)
	}
}

func btJoinStrings(a []string, sep string) string {
	if len(a) == 0 {
		return ""
	}
