func exist(board [][]byte, word string) bool {
	m, n := len(board), len(board[0])
	for r := 0; r < m; r++ {
		for c := 0; c < n; c++ {
			if btWordSearch(board, word, m, n, r, c, 0) {
				return true
			}
		}
	}
	return false
}

func btWordSearch(board [][]byte, word string, m, n, r, c, idx int) bool {
	if idx == len(word) {
		return true
	}
	if r < 0 || r >= m || c < 0 || c >= n || board[r][c] != word[idx] {
		return false
	}
	tmp := board[r][c]
	board[r][c] = ''#''
	found := btWordSearch(board, word, m, n, r+1, c, idx+1) ||
		btWordSearch(board, word, m, n, r-1, c, idx+1) ||
		btWordSearch(board, word, m, n, r, c+1, idx+1) ||
		btWordSearch(board, word, m, n, r, c-1, idx+1)
	board[r][c] = tmp
	return found
}
