func kthLargest(a []int, k int) int {
	n := len(a)
	arr := make([]int, n)
	copy(arr, a)
	return btQuickSelect(arr, 0, n-1, n+1-k)
}

func kthSmallest(a []int, k int) int {
	n := len(a)
	arr := make([]int, n)
	copy(arr, a)
	return btQuickSelect(arr, 0, n-1, k)
}

func btQuickSelect(a []int, start, end, k int) int {
	if start == end {
		return a[start]
	}
	pivotIdx := btPartition(a, start, end)
	if pivotIdx == k-1 {
		return a[pivotIdx]
	}
	if k-1 < pivotIdx {
		return btQuickSelect(a, start, pivotIdx-1, k)
	}
	return btQuickSelect(a, pivotIdx+1, end, k)
}

func btPartition(a []int, start, end int) int {
	pivot := a[start]
	pos := start
	for i := start + 1; i <= end; i++ {
		if a[i] < pivot {
			pos++
			a[pos], a[i] = a[i], a[pos]
		}
	}
	a[start], a[pos] = a[pos], a[start]
	return pos
}
