func findMissingInAp(a []int) int {
	n := len(a)
	low, high := 0, n-1
	diff := (a[high] - a[low]) / n
	for low <= high {
		mid := low + (high-low)/2
		expected := a[0] + mid*diff
		if a[mid] == expected {
			low = mid + 1
		} else {
			high = mid - 1
		}
	}
	return a[0] + low*diff
}
