func countOccurrence(a []int, key int) int {
	if len(a) == 0 {
		return 0
	}
	left := btFirstGreaterOrEqual(a, key)
	if left == len(a) || a[left] != key {
		return 0
	}
	right := btFirstGreater(a, key)
	return right - left
}

func btFirstGreaterOrEqual(a []int, key int) int {
	low, high := 0, len(a)-1
	for low < high {
		mid := low + (high-low)/2
		if a[mid] < key {
			low = mid + 1
		} else {
			high = mid
		}
	}
	if a[low] < key {
		return len(a)
	}
	return low
}

func btFirstGreater(a []int, key int) int {
	low, high := 0, len(a)
	for low < high {
		mid := low + (high-low)/2
		if a[mid] <= key {
			low = mid + 1
		} else {
			high = mid
		}
	}
	return low
}
