func sortSquares(a []int) []int {
	n := len(a)
	res := make([]int, n)
	i, j := 0, n-1
	for k := n - 1; k >= 0; k-- {
		if absInt(a[i]) > absInt(a[j]) {
			res[k] = a[i] * a[i]
			i++
		} else {
			res[k] = a[j] * a[j]
			j--
		}
	}
	return res
}

func absInt(x int) int {
	if x < 0 {
		return -x
	}
	return x
}
