func possiblyEquals(s1 string, s2 string) bool {
	m, n := len(s1), len(s2)
	memo := map[[3]int]bool{}
	return btPossiblyEquals(s1, s2, 0, 0, 0, m, n, memo)
}

func btPossiblyEquals(s1, s2 string, i, j, diff, m, n int, memo map[[3]int]bool) bool {
	if i == m && j == n {
		return diff == 0
	}
	k := [3]int{i, j, diff}
	if v, ok := memo[k]; ok {
		return v
	}
	res := false
	if i < m && s1[i] >= ''0'' && s1[i] <= ''9'' {
		num := 0
		for p := i; p < m && s1[p] >= ''0'' && s1[p] <= ''9''; p++ {
			num = num*10 + int(s1[p]-''0'')
			if btPossiblyEquals(s1, s2, p+1, j, diff+num, m, n, memo) {
				res = true
				break
			}
		}
	} else if j < n && s2[j] >= ''0'' && s2[j] <= ''9'' {
		num := 0
		for p := j; p < n && s2[p] >= ''0'' && s2[p] <= ''9''; p++ {
			num = num*10 + int(s2[p]-''0'')
			if btPossiblyEquals(s1, s2, i, p+1, diff-num, m, n, memo) {
				res = true
				break
			}
		}
	} else if diff > 0 && j < n {
		if s2[j] >= ''a'' && s2[j] <= ''z'' {
			res = btPossiblyEquals(s1, s2, i, j+1, diff-1, m, n, memo)
		}
	} else if diff < 0 && i < m {
		if s1[i] >= ''a'' && s1[i] <= ''z'' {
			res = btPossiblyEquals(s1, s2, i+1, j, diff+1, m, n, memo)
		}
	} else if diff == 0 && i < m && j < n {
		if s1[i] >= ''a'' && s1[i] <= ''z'' && s2[j] >= ''a'' && s2[j] <= ''z'' {
			res = s1[i] == s2[j] && btPossiblyEquals(s1, s2, i+1, j+1, 0, m, n, memo)
		}
	}
	memo[k] = res
	return res
}
