func makeChange(n int, coins []int) int64 {
	if n < 0 {
		return 0
	}
	if n == 0 {
		return 1
	}
	if len(coins) == 0 {
		return 0
	}
	dp := make([]int64, n+1)
	dp[0] = 1
	for _, coin := range coins {
		for i := coin; i <= n; i++ {
			dp[i] += dp[i-coin]
		}
	}
	return dp[n]
