func btEditDistance(word1, word2 string, i, j int, memo map[[2]int]int) int {
	if i == len(word1) {
		return len(word2) - j
	}
	if j == len(word2) {
		return len(word1) - i
	}
	key := [2]int{i, j}
	if v, ok := memo[key]; ok {
		return v
	}
	if word1[i] == word2[j] {
		memo[key] = btEditDistance(word1, word2, i+1, j+1, memo)
		return memo[key]
	}
	memo[key] = 1 + min(
		btEditDistance(word1, word2, i+1, j+1, memo),
		min(btEditDistance(word1, word2, i+1, j, memo), btEditDistance(word1, word2, i, j+1, memo)),
	)
	return memo[key]
}
