func minHeightShelves(books [][]int, shelfWidth int) int {
	n := len(books)
	dp := make([]int, n+1)
	for i := 1; i <= n; i++ {
		dp[i] = 1 << 30
	}
	for i := 1; i <= n; i++ {
		w, h := 0, 0
		for j := i; j >= 1; j-- {
			w += books[j-1][0]
			if w > shelfWidth {
				break
			}
			if books[j-1][1] > h {
				h = books[j-1][1]
			}
			if dp[j-1]+h < dp[i] {
				dp[i] = dp[j-1] + h
			}
		}
	}
	return dp[n]
}
