func knapsack(weights []int, values []int, capacity int) int {
	dp := make([]int, capacity+1)
	for i := range weights {
		w, v := weights[i], values[i]
		for c := capacity; c >= w; c-- {
			if dp[c-w]+v > dp[c] {
				dp[c] = dp[c-w] + v
			}
		}
	}
	return dp[capacity]
}
