func longestIncreasingSubsequence(nums []int) int {
	tails := []int{}
	for _, x := range nums {
		low, high := 0, len(tails)
		for low < high {
			mid := low + (high-low)/2
			if tails[mid] < x {
				low = mid + 1
			} else {
				high = mid
			}
		}
		if low == len(tails) {
			tails = append(tails, x)
		} else {
			tails[low] = x
		}
	}
	return len(tails)
}
