	n := len(nums)
	if n == 0 {
		return 0
	}
	dp := make([]int, n)
	res := 1
	for i := range dp {
		dp[i] = 1
	}
	for i := 1; i < n; i++ {
		for j := 0; j < i; j++ {
			if nums[j] < nums[i] && dp[j]+1 > dp[i] {
				dp[i] = dp[j] + 1
