func longestValidParentheses(s string) int {
	stack := []int{-1}
	res := 0
	for i := 0; i < len(s); i++ {
		if s[i] == ''('' {
			stack = append(stack, i)
		} else {
			stack = stack[:len(stack)-1]
			if len(stack) == 0 {
				stack = append(stack, i)
			} else {
				l := i - stack[len(stack)-1]
				if l > res {
					res = l
				}
			}
		}
	}
	return res
}
