func maximumANDSum(nums []int, numSlots int) int {
	memo := map[int]int{}
	return btMaxAndSum(nums, 0, 0, numSlots, memo)
}

func btMaxAndSum(nums []int, idx, state, numSlots int, memo map[int]int) int {
	if idx == len(nums) {
		return 0
	}
	if v, ok := memo[state]; ok {
		return v
	}
	res := 0
	for slot := 1; slot <= numSlots; slot++ {
		occ := (state >> (2 * (slot - 1))) & 3
		if occ < 2 {
			next := state + (1 << (2 * (slot - 1)))
			val := (nums[idx] & slot) + btMaxAndSum(nums, idx+1, next, numSlots, memo)
			if val > res {
				res = val
			}
		}
	}
	memo[state] = res
	return res
}
