func maxPoints(points [][]int) int64 {
	n := len(points[0])
	dp := make([]int64, n)
	for j := 0; j < n; j++ {
		dp[j] = int64(points[0][j])
	}
	for i := 1; i < len(points); i++ {
		left := make([]int64, n)
		left[0] = dp[0]
		for j := 1; j < n; j++ {
			left[j] = dp[j]
			if left[j-1]-1 > left[j] {
				left[j] = left[j-1] - 1
			}
		}
		right := make([]int64, n)
		right[n-1] = dp[n-1]
		for j := n - 2; j >= 0; j-- {
			right[j] = dp[j]
			if right[j+1]-1 > right[j] {
				right[j] = right[j+1] - 1
			}
		}
		for j := 0; j < n; j++ {
			best := left[j]
			if right[j] > best {
				best = right[j]
			}
			dp[j] = int64(points[i][j]) + best
		}
	}
	var res int64
	for _, v := range dp {
		if v > res {
			res = v
		}
	}
	return res
}
