func minPathSumInMatrix(grid [][]int) int {
	m, n := len(grid), len(grid[0])
	for r := 1; r < m; r++ {
		grid[r][0] += grid[r-1][0]
	}
	for c := 1; c < n; c++ {
		grid[0][c] += grid[0][c-1]
	}
	for r := 1; r < m; r++ {
		for c := 1; c < n; c++ {
			grid[r][c] += min(grid[r-1][c], grid[r][c-1])
