func btMinPathSum(grid [][]int, r, c int, memo map[[2]int]int) int {
	if r == 0 && c == 0 {
		return grid[0][0]
	}
	key := [2]int{r, c}
	if v, ok := memo[key]; ok {
		return v
	}
	best := 1 << 30
	if r > 0 {
		best = min(best, btMinPathSum(grid, r-1, c, memo))
	}
	if c > 0 {
		best = min(best, btMinPathSum(grid, r, c-1, memo))
	}
	memo[key] = grid[r][c] + best
	return memo[key]
}
