func numberOfWaysDecodingBase26(s string) int {
	if len(s) == 0 || s[0] == ''0'' {
		return 0
	}
	prev, cur := 1, 1
	for i := 1; i < len(s); i++ {
		next := 0
		if s[i] != ''0'' {
			next = cur
		}
		two := int(s[i-1]-''0'')*10 + int(s[i]-''0'')
		if two >= 10 && two <= 26 {
			next += prev
		}
		prev, cur = cur, next
	}
	return cur
}
