func racecar(target int) int {
	vis := map[[2]int]bool{{0, 1}: true}
	q := [][2]int{{0, 1}}
	steps := 0
	for len(q) > 0 {
		steps++
		sz := len(q)
		for i := 0; i < sz; i++ {
			pos, speed := q[0][0], q[0][1]
			q = q[1:]
			np, ns := pos+speed, speed*2
			if np == target {
				return steps
			}
			if np > 0 && np < 2*target && !vis[[2]int{np, ns}] {
				vis[[2]int{np, ns}] = true
				q = append(q, [2]int{np, ns})
			}
			rs := -1
			if speed < 0 {
				rs = 1
			}
			if !vis[[2]int{pos, rs}] {
				vis[[2]int{pos, rs}] = true
				q = append(q, [2]int{pos, rs})
			}
		}
	}
	return -1
}
