def racecar(target: int) -> int:
    vis = {(0, 1)}
    q = deque([(0, 1)])
    steps = 0
    while q:
        steps += 1
        for _ in range(len(q)):
            pos, speed = q.popleft()
            np, ns = pos + speed, speed * 2
            if np == target:
                return steps
            if 0 < np < 2 * target and (np, ns) not in vis:
                vis.add((np, ns))
                q.append((np, ns))
