  ('imp-80-race-car', 'java', 'Solution.java', 'import java.util.ArrayDeque;
import java.util.HashSet;
import java.util.Set;

class Solution {
    public int racecar(int target) {
        Set<Long> vis = new HashSet<>();
        ArrayDeque<int[]> q = new ArrayDeque<>();
        vis.add(key(0, 1));
        q.add(new int[]{0, 1});
        int steps = 0;
        while (!q.isEmpty()) {
            steps++;
            int sz = q.size();
            for (int i = 0; i < sz; i++) {
                int[] cur = q.poll();
                int pos = cur[0], speed = cur[1];
                int np = pos + speed, ns = speed * 2;
                if (np == target) {
                    return steps;
                }
                if (np > 0 && np < 2 * target && !vis.contains(key(np, ns))) {
                    vis.add(key(np, ns));
                    q.add(new int[]{np, ns});
                }
                int rs = speed < 0 ? 1 : -1;
                if (!vis.contains(key(pos, rs))) {
                    vis.add(key(pos, rs));
                    q.add(new int[]{pos, rs});
                }
            }
        }
        return -1;
    }

    private static long key(int a, int b) {
        return ((long) a << 32) ^ (b & 0xffffffffL);
    }
