import "strings"

func wordsTyping(sentence []string, rows int, cols int) int {
	s := strings.Join(sentence, " ") + " "
	n := len(s)
	start := 0
	for i := 0; i < rows; i++ {
		start += cols
		if s[start%n] == '' '' {
			start++
		} else {
			for start > 0 && s[(start-1)%n] != '' '' {
				start--
			}
		}
	}
	return start / n
}
