func checkRecord(n int) int {
	const mod = 1_000_000_007
	dp := [2][3]int{}
	dp[0][0] = 1
	dp[0][1] = 1
	dp[1][0] = 1
	for i := 2; i <= n; i++ {
		nd := [2][3]int{}
		nd[0][0] = (dp[0][0] + dp[0][1] + dp[0][2]) % mod
		nd[1][0] = (dp[1][0] + dp[1][1] + dp[1][2]) % mod
		nd[0][1] = dp[0][0]
		nd[0][2] = dp[0][1]
		nd[1][1] = dp[1][0]
		nd[1][2] = dp[1][1]
		nd[1][0] = (nd[1][0] + dp[0][0] + dp[0][1] + dp[0][2]) % mod
		dp = nd
	}
	res := 0
	for a := 0; a < 2; a++ {
		for l := 0; l < 3; l++ {
			res = (res + dp[a][l]) % mod
		}
	}
	return res
}
