func findDuplicateAndMissing(nums []int) (int, int) {
	n := len(nums)
	xorAll := 0
	for i := 1; i <= n; i++ {
		xorAll ^= i
	}
	for _, v := range nums {
		xorAll ^= v
	}
	rightBit := xorAll & -xorAll
	x, y := 0, 0
	for i := 1; i <= n; i++ {
		if i&rightBit != 0 {
			x ^= i
		} else {
			y ^= i
		}
	}
	for _, v := range nums {
		if v&rightBit != 0 {
			x ^= v
		} else {
			y ^= v
		}
	}
	if nums[x-1] == x {
		return x, y
	}
	return y, x
}
