def maxRectangleInHistogram(heights: List[int]) -> int:
    stack: List[int] = []
    best = 0
    n = len(heights)
    for i in range(n + 1):
        h = heights[i] if i < n else 0
        while stack and h < heights[stack[-1]]:
            top = stack.pop()
            width = i
            if stack:
                width = i - stack[-1] - 1
            if heights[top] * width > best:
                best = heights[top] * width
        stack.append(i)
