class Solution {
    long maxRectangleInHistogram(long[] heights) {
        int[] stack = new int[heights.length + 1];
        int sp = 0;
        long best = 0;
        int n = heights.length;
        for (int i = 0; i <= n; i++) {
            long h = 0;
            if (i < n) {
                h = heights[i];
            }
            while (sp > 0 && h < heights[stack[sp - 1]]) {
                int top = stack[--sp];
                long width = i;
                if (sp > 0) {
                    width = i - stack[sp - 1] - 1;
                }
                if (heights[top] * width > best) {
                    best = heights[top] * width;
                }
            }
            stack[sp++] = i;
        }
        return best;
    }
}', false, 2),
