class Solution {
    public void rotateArray(long[] nums, int k) {
        int n = nums.length;
        if (n == 0) {
            return;
        }
        k %= n;
        reverse(nums, 0, n - 1);
        reverse(nums, 0, k - 1);
        reverse(nums, k, n - 1);
    }

    private void reverse(long[] nums, int l, int r) {
        while (l < r) {
            long tmp = nums[l];
            nums[l] = nums[r];
            nums[r] = tmp;
            l++;
            r--;
        }
    }
}', false, 2),
