func taskScheduler(tasks []byte, n int) int {
	freq := map[byte]int{}
	maxF := 0
	for _, t := range tasks {
		freq[t]++
		if freq[t] > maxF {
			maxF = freq[t]
		}
	}
	cntMax := 0
	for _, f := range freq {
		if f == maxF {
			cntMax++
		}
	}
	idle := (maxF-1)*n + cntMax
	if idle < len(tasks) {
		return len(tasks)
	}
	return idle
}
