class Solution {
    long taskScheduler(byte[] tasks, long n) {
        Map<Byte, Long> freq = new HashMap<>();
        long maxF = 0;
        for (byte t : tasks) {
            long f = freq.getOrDefault(t, 0L) + 1;
            freq.put(t, f);
            if (f > maxF) {
                maxF = f;
            }
        }
        long cntMax = 0;
        for (long f : freq.values()) {
            if (f == maxF) {
                cntMax++;
            }
        }
        long idle = (maxF - 1) * n + cntMax;
        if (idle < tasks.length) {
            return tasks.length;
        }
        return idle;
    }
}', false, 2),
