func trapRainWater(height []int) int {
	if len(height) == 0 {
		return 0
	}
	l, r := 0, len(height)-1
	leftMax, rightMax := height[l], height[r]
	ans := 0
	for l < r {
		if leftMax < rightMax {
			l++
			if height[l] > leftMax {
				leftMax = height[l]
			} else {
				ans += leftMax - height[l]
			}
		} else {
			r--
			if height[r] > rightMax {
				rightMax = height[r]
			} else {
				ans += rightMax - height[r]
			}
		}
	}
	return ans
}
