  ('prep-database-department-top-three-salaries', 'go', 'solution.go', 'package main
import (
	"sort"
)


type Employee struct {
	ID           int
	Name         string
	Salary       int
	DepartmentID int
}

type Department struct {
	ID   int
	Name string
}

type Result struct {
	Department string
	Employee   string
	Salary     int
}

func auditHighEarners(employees []Employee, departments []Department) []Result {
	if len(employees) == 0 || len(departments) == 0 {
		return []Result{}
	}

	deptNames := make(map[int]string)
	for _, dept := range departments {
		deptNames[dept.ID] = dept.Name
	}

	groupedEmployees := make(map[int][]Employee)
	for _, emp := range employees {
		if _, exists := deptNames[emp.DepartmentID]; exists {
			groupedEmployees[emp.DepartmentID] = append(groupedEmployees[emp.DepartmentID], emp)
		}
	}

	var results []Result

	var sortedDeptIDs []int
	for deptID := range groupedEmployees {
		sortedDeptIDs = append(sortedDeptIDs, deptID)
	}
	sort.Ints(sortedDeptIDs)

	for _, deptID := range sortedDeptIDs {
		deptEmployees := groupedEmployees[deptID]
		deptName := deptNames[deptID]

		uniqueSalariesMap := make(map[int]bool)
		for _, emp := range deptEmployees {
			uniqueSalariesMap[emp.Salary] = true
		}

		uniqueSalaries := make([]int, 0, len(uniqueSalariesMap))
		for sal := range uniqueSalariesMap {
			uniqueSalaries = append(uniqueSalaries, sal)
		}

		sort.Slice(uniqueSalaries, func(i, j int) bool {
			return uniqueSalaries[i] > uniqueSalaries[j]
		})

		limit := 3
		if len(uniqueSalaries) < limit {
			limit = len(uniqueSalaries)
		}

		topSalariesSet := make(map[int]bool)
		for i := 0; i < limit; i++ {
			topSalariesSet[uniqueSalaries[i]] = true
		}

		var deptHighEarners []Result
		for _, emp := range deptEmployees {
			if topSalariesSet[emp.Salary] {
				deptHighEarners = append(deptHighEarners, Result{
					Department: deptName,
					Employee:   emp.Name,
					Salary:     emp.Salary,
				})
			}
		}

		sort.Slice(deptHighEarners, func(i, j int) bool {
			if deptHighEarners[i].Salary != deptHighEarners[j].Salary {
				return deptHighEarners[i].Salary > deptHighEarners[j].Salary
			}
			return deptHighEarners[i].Employee < deptHighEarners[j].Employee
		})

		results = append(results, deptHighEarners...)
	}

	return results
}
