  ('prep-design-amount-of-new-area-painted-each-day', 'go', 'solution.go', 'package main
func amountPainted(paint [][]int) []int {
	maxR := 0
	for _, p := range paint {
		if p[1] > maxR {
			maxR = p[1]
		}
	}
	jump := make([]int, maxR+1)
	res := make([]int, len(paint))
	for day, p := range paint {
		l, r := p[0], p[1]
		cnt := 0
		for i := l; i < r; {
			if jump[i] == 0 {
				jump[i] = i + 1
				cnt++
				i++
			} else {
				next := jump[i]
				jump[i] = r
				i = next
			}
		}
		res[day] = cnt
	}
	return res
}
