type TicTacToe struct {
	rows, cols     []int
	diag, antiDiag int
	n              int
}

func Constructor(n int) TicTacToe {
	return TicTacToe{rows: make([]int, n), cols: make([]int, n), n: n}
}

func (t *TicTacToe) Move(row, col, player int) int {
	add := 1
	if player == 2 {
		add = -1
	}
	t.rows[row] += add
	t.cols[col] += add
	if row == col {
		t.diag += add
	}
	if row+col == t.n-1 {
		t.antiDiag += add
	}
	if abs(t.rows[row]) == t.n || abs(t.cols[col]) == t.n || abs(t.diag) == t.n || abs(t.antiDiag) == t.n {
		return player
	}
	return 0
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}
