type DetectSquares struct {
	cnt map[[2]int]int
	pts [][2]int
}

func Constructor() DetectSquares { return DetectSquares{cnt: map[[2]int]int{}} }

func (d *DetectSquares) Add(point []int) {
	p := [2]int{point[0], point[1]}
	d.cnt[p]++
	d.pts = append(d.pts, p)
}

func (d *DetectSquares) Count(point []int) int {
	qx, qy, res := point[0], point[1], 0
	for _, p := range d.pts {
		px, py := p[0], p[1]
		if px == qx || abs(px-qx) != abs(py-qy) {
			continue
		}
		res += d.cnt[[2]int{px, qy}] * d.cnt[[2]int{qx, py}]
	}
	return res
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}
