  ('prep-design-design-an-expression-tree-with-evaluate-function', 'go', 'solution.go', 'package main
import "strconv"


type ExprNode struct {
	val         string
	left, right *ExprNode
}

func (n *ExprNode) Evaluate() int {
	if n.left == nil {
		v, _ := strconv.Atoi(n.val)
		return v
	}
	l, r := n.left.Evaluate(), n.right.Evaluate()
	switch n.val {
	case "+":
		return l + r
	case "-":
		return l - r
	case "*":
		return l * r
	case "/":
		return l / r
	}
	return 0
}

func buildTree(postfix []string) *ExprNode {
	var stack []*ExprNode
	for _, tok := range postfix {
		if tok == "+" || tok == "-" || tok == "*" || tok == "/" {
			r, l := stack[len(stack)-1], stack[len(stack)-2]
			stack = stack[:len(stack)-2]
			stack = append(stack, &ExprNode{tok, l, r})
		} else {
			stack = append(stack, &ExprNode{val: tok})
		}
	}
	return stack[0]
}

type TreeBuilder struct{}

func (tb *TreeBuilder) BuildTree(postfix []string) *ExprNode {
	return buildTree(postfix)
}
