  ('prep-design-guess-the-word', 'go', 'solution.go', 'package main
type Master interface {
	Guess(word string) int
}

type FakeMaster struct {
	secret string
	calls  int
}

func (fm *FakeMaster) Guess(word string) int {
	fm.calls++
	c := 0
	for i := range word {
		if word[i] == fm.secret[i] {
			c++
		}
	}
	return c
}

func findSecretWord(words []string, master Master) {
	match := func(a, b string) int {
		c := 0
		for i := range a {
			if a[i] == b[i] {
				c++
			}
		}
		return c
	}
	cands := append([]string{}, words...)
	for i := 0; i < 10 && len(cands) > 0; i++ {
		guess := cands[0]
		m := master.Guess(guess)
		if m == 6 {
			return
		}
		var next []string
		for _, w := range cands {
			if w != guess && match(w, guess) == m {
				next = append(next, w)
			}
		}
		cands = next
	}
}
