type loadBalancer struct {
	servers []string
	index   int
}

func newLoadBalancer(servers []string) *loadBalancer {
	return &loadBalancer{servers: append([]string(nil), servers...)}
}

func (lb *loadBalancer) nextServer() (string, bool) {
	if len(lb.servers) == 0 {
		return "", false
	}
	server := lb.servers[lb.index]
	lb.index = (lb.index + 1) % len(lb.servers)
	return server, true
}

func (lb *loadBalancer) addServer(server string) {
	lb.servers = append(lb.servers, server)
}

func (lb *loadBalancer) removeServer(server string) {
	for i, s := range lb.servers {
		if s == server {
			lb.servers = append(lb.servers[:i], lb.servers[i+1:]...)
			if lb.index >= len(lb.servers) {
				lb.index = 0
			}
			return
		}
	}
}
