  ('prep-design-meeting-rooms-iii', 'go', 'solution.go', 'package main
import (
	"container/heap"
	"sort"
)


type intHeap []int

func (h intHeap) Len() int            { return len(h) }
func (h intHeap) Less(i, j int) bool  { return h[i] < h[j] }
func (h intHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *intHeap) Push(x interface{}) { *h = append(*h, x.(int)) }
func (h *intHeap) Pop() interface{}   { old := *h; x := old[len(old)-1]; *h = old[:len(old)-1]; return x }

type busyItem struct{ end, room int }
type busyHeap []busyItem

func (h busyHeap) Len() int { return len(h) }
func (h busyHeap) Less(i, j int) bool {
	if h[i].end == h[j].end {
		return h[i].room < h[j].room
	}
	return h[i].end < h[j].end
}
func (h busyHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *busyHeap) Push(x interface{}) { *h = append(*h, x.(busyItem)) }
func (h *busyHeap) Pop() interface{} {
	old := *h
	x := old[len(old)-1]
	*h = old[:len(old)-1]
	return x
}

func mostBooked(n int, meetings [][]int) int {
	sort.Slice(meetings, func(i, j int) bool { return meetings[i][0] < meetings[j][0] })
	avail := &intHeap{}
	for i := 0; i < n; i++ {
		heap.Push(avail, i)
	}
	busy := &busyHeap{}
	cnt := make([]int, n)
	for _, m := range meetings {
		s, e := m[0], m[1]
		for busy.Len() > 0 && (*busy)[0].end <= s {
			heap.Push(avail, heap.Pop(busy).(busyItem).room)
		}
		if avail.Len() > 0 {
			r := heap.Pop(avail).(int)
			cnt[r]++
			heap.Push(busy, busyItem{e, r})
		} else {
			b := heap.Pop(busy).(busyItem)
			cnt[b.room]++
			heap.Push(busy, busyItem{b.end + (e - s), b.room})
		}
	}
	res := 0
	for i := 1; i < n; i++ {
		if cnt[i] > cnt[res] {
			res = i
		}
	}
	return res
}
