	name, ok := pd.contacts[number]
	return name, ok
}

func (pd *phoneDirectory) suggest(prefix string) []string {
	node := pd.root
	for i := 0; i < len(prefix); i++ {
		ch := prefix[i]
		if node.children[ch] == nil {
			return nil
		}
		node = node.children[ch]
	}
	return append([]string(nil), node.names...)
}
