			s.n4 = read4(s.buf4[:])
			s.i4 = 0
			if s.n4 == 0 {
				break
			}
		}
		buf[total] = s.buf4[s.i4]
		s.i4++
		total++
	}
	return total
}

func solution(read4In func([]byte) int) func([]byte, int) int {
	read4 = read4In
	s := Constructor()
	return s.Read
}
