type RLEIterator struct {
	enc []int
	idx int
}

func Constructor(encoding []int) RLEIterator { return RLEIterator{enc: encoding} }

func (it *RLEIterator) Next(n int) int {
	for it.idx < len(it.enc) {
		if it.enc[it.idx] >= n {
			it.enc[it.idx] -= n
			return it.enc[it.idx+1]
		}
		n -= it.enc[it.idx]
		it.idx += 2
	}
	return -1
}
