import "container/heap"


type maxPriceHeap [][2]int
func (h maxPriceHeap) Len() int            { return len(h) }
func (h maxPriceHeap) Less(i, j int) bool  { return h[i][0] > h[j][0] }
func (h maxPriceHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *maxPriceHeap) Push(x interface{}) { *h = append(*h, x.([2]int)) }
func (h *maxPriceHeap) Pop() interface{} {
	old := *h
	x := old[len(old)-1]
	*h = old[:len(old)-1]
	return x
}

type minPriceHeap [][2]int

func (h minPriceHeap) Len() int            { return len(h) }
func (h minPriceHeap) Less(i, j int) bool  { return h[i][0] < h[j][0] }
func (h minPriceHeap) Swap(i, j int)       { h[i], h[j] = h[j], h[i] }
func (h *minPriceHeap) Push(x interface{}) { *h = append(*h, x.([2]int)) }
func (h *minPriceHeap) Pop() interface{} {
	old := *h
	x := old[len(old)-1]
	*h = old[:len(old)-1]
	return x
}

type StockPrice struct {
	records    map[int]int
	latestTime int
	maxH       *maxPriceHeap
	minH       *minPriceHeap
}

func Constructor() StockPrice {
	return StockPrice{records: map[int]int{}, maxH: &maxPriceHeap{}, minH: &minPriceHeap{}}
}

func (sp *StockPrice) Update(timestamp, price int) {
	sp.records[timestamp] = price
	if timestamp > sp.latestTime {
		sp.latestTime = timestamp
	}
	heap.Push(sp.maxH, [2]int{price, timestamp})
	heap.Push(sp.minH, [2]int{price, timestamp})
}

func (sp *StockPrice) Current() int { return sp.records[sp.latestTime] }

func (sp *StockPrice) Maximum() int {
	for (*sp.maxH)[0][0] != sp.records[(*sp.maxH)[0][1]] {
		heap.Pop(sp.maxH)
	}
	return (*sp.maxH)[0][0]
}

func (sp *StockPrice) Minimum() int {
	for (*sp.minH)[0][0] != sp.records[(*sp.minH)[0][1]] {
		heap.Pop(sp.minH)
	}
	return (*sp.minH)[0][0]
}
