def partition_kth(a: List[int], lo: int, hi: int) -> int:
    pivot = a[hi]
    store = lo
    for i in range(lo, hi):
        if a[i] <= pivot:
            a[i], a[store] = a[store], a[i]
            store += 1
    a[store], a[hi] = a[hi], a[store]
    return store


def find_kth_largest(a: List[int], k: int) -> int:
    target = len(a) - k
    lo, hi = 0, len(a) - 1
    while lo < hi:
        p = partition_kth(a, lo, hi)
        if p == target:
            return a[p]
        if p < target:
            lo = p + 1
        else:
            hi = p - 1
