  ('prep-hash-maps-find-kth-largest', 'java', 'Solution.java', 'import java.util.*;

class Solution {
    static int partitionKth(long[] a, int lo, int hi) {
        long pivot = a[hi];
        int store = lo;
        for (int i = lo; i < hi; i++) {
            if (a[i] <= pivot) {
                long t = a[i];
                a[i] = a[store];
                a[store] = t;
                store++;
            }
        }
        long t = a[store];
        a[store] = a[hi];
        a[hi] = t;
        return store;
    }

    static long findKthLargest(long[] a, int k) {
        int target = a.length - k;
        int lo = 0, hi = a.length - 1;
        while (lo < hi) {
            int p = partitionKth(a, lo, hi);
            if (p == target) {
                return a[p];
            }
            if (p < target) {
                lo = p + 1;
            } else {
                hi = p - 1;
            }
        }
        return a[lo];
    }
}', false, 2),
