	word string
	cnt  int
}

func findTopKTweetWordsInLast(tweets []Tweet, now int, window int, k int) []string {
	counts := make(map[string]int)
	for _, tw := range tweets {
		if tw.Time > now || now-tw.Time > window {
			continue
		}
		counts[tw.Word]++
	}
	items := make([]wordFreq, 0, len(counts))
	for word, cnt := range counts {
		items = append(items, wordFreq{word, cnt})
	}
	sort.Slice(items, func(i, j int) bool {
		return items[i].cnt > items[j].cnt
	})
	if k > len(items) {
		k = len(items)
	}
	res := make([]string, k)
	for i := 0; i < k; i++ {
		res[i] = items[i].word
	}
	return res
}
