class Solution {
    static final class Student {
        final long id;
        final String name;

        Student(long id, String name) {
            this.id = id;
            this.name = name;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (!(o instanceof Student)) return false;
            Student s = (Student) o;
            return id == s.id && Objects.equals(name, s.name);
        }

        @Override
        public int hashCode() {
            return Objects.hash(id, name);
        }
    }

    Map<Student, Long> objectAsKey(List<Student> students, Map<Student, Long> grades) {
        Map<Student, Long> result = new HashMap<>(students.size());
        for (Student s : students) {
            Long g = grades.get(s);
            if (g != null) {
                result.put(s, g);
            }
        }
        return result;
    }
}', false, 2),
  ('prep-hash-maps-remove-duplicate-contacts', 'go', 'solution.go', 'package main
type Contact struct {
	ID     int
	Emails []string
}

func removeDuplicateContacts(contacts []Contact) []Contact {
	parent := make(map[int]int)
	find := func(x int) int {
		for parent[x] != x {
			parent[x] = parent[parent[x]]
			x = parent[x]
		}
		return x
	}
	union := func(a, b int) {
		ra, rb := find(a), find(b)
		if ra != rb {
			parent[rb] = ra
		}
	}
	emailOwner := make(map[string]int)
	byID := make(map[int]Contact)
	for _, c := range contacts {
		parent[c.ID] = c.ID
		byID[c.ID] = c
		for _, e := range c.Emails {
			if owner, ok := emailOwner[e]; ok {
				union(c.ID, owner)
			} else {
				emailOwner[e] = c.ID
			}
		}
	}
	seen := make(map[int]bool)
	var out []Contact
	for _, c := range contacts {
		root := find(c.ID)
		if seen[root] {
			continue
		}
		seen[root] = true
		out = append(out, byID[root])
	}
	return out
}
