import (
	"sort"
)


type Interval struct {
	Start, End int
}

func countRange(ins []Interval) int {
	if len(ins) == 0 {
		return 0
	}
	sorted := make([]Interval, len(ins))
	copy(sorted, ins)
	sort.Slice(sorted, func(i, j int) bool {
		return sorted[i].Start < sorted[j].Start
	})
	rangeSum := 0
	i := 0
	for i < len(sorted) {
		start := sorted[i].Start
		end := sorted[i].End
		j := i + 1
		for j < len(sorted) && sorted[j].Start <= end+1 {
			if sorted[j].End > end {
				end = sorted[j].End
			}
			j++
		}
		rangeSum += end - start + 1
		i = j
	}
	return rangeSum
}
