			heights[ev.Height]--
			if heights[ev.Height] == 0 {
				delete(heights, ev.Height)
			}
		}
		newMax := 0
		for h := range heights {
			if h > newMax {
				newMax = h
			}
		}
		if newMax != currMax {
			res = append(res, SkyPoint{X: ev.X, Height: newMax})
			currMax = newMax
		}
	}
	return res
