type Point struct {
	X, Y int
}

func distPoint(p1, p2 Point) int {
	dx := p1.X - p2.X
	dy := p1.Y - p2.Y
	return dx*dx + dy*dy
}

func isSquare(p1, p2, p3, p4 Point) bool {
	d1 := distPoint(p1, p2)
	if d1 == 0 {
		return false
	}
	d2 := distPoint(p1, p3)
	d3 := distPoint(p1, p4)
	d4 := distPoint(p2, p3)
	d5 := distPoint(p2, p4)
	d6 := distPoint(p3, p4)
	pairs := []int{d1, d2, d3, d4, d5, d6}
	counts := make(map[int]int)
	for _, d := range pairs {
		counts[d]++
	}
	return counts[d1] == 4 && counts[d2] == 2 && d1 != d2
}
