import "sort"


func minMeetingRooms(intervals [][]int) int {
	n := len(intervals)
	starts := make([]int, n)
	ends := make([]int, n)
	for i, v := range intervals {
		starts[i] = v[0]
		ends[i] = v[1]
	}
	sort.Ints(starts)
	sort.Ints(ends)
	rooms, endIdx := 0, 0
	for i := 0; i < n; i++ {
		if starts[i] < ends[endIdx] {
			rooms++
		} else {
			endIdx++
		}
	}
	return rooms
}
