func canAttendAll(ins []Interval) bool {
	if len(ins) <= 1 {
		return true
	}
	sorted := make([]Interval, len(ins))
	copy(sorted, ins)
	sort.Slice(sorted, func(i, j int) bool {
		return sorted[i].Start < sorted[j].Start
	})
	for i := 1; i < len(sorted); i++ {
		if sorted[i].Start < sorted[i-1].End {
			return false
		}
	}
	return true
