def addTwoNumbers(l1: Optional[ListNode], l2: Optional[ListNode]) -> Optional[ListNode]:
    dummy = ListNode()
    cur = dummy
    carry = 0
    while l1 is not None or l2 is not None or carry > 0:
        s = carry
        if l1 is not None:
            s += l1.val
            l1 = l1.next
        if l2 is not None:
