func deepCopyRandomPointers(head *RandomNode) *RandomNode {
	if head == nil {
		return nil
	}
	seen := map[*RandomNode]*RandomNode{}
	var clone func(n *RandomNode) *RandomNode
	clone = func(n *RandomNode) *RandomNode {
		if n == nil {
			return nil
		}
		if c, ok := seen[n]; ok {
			return c
		}
		c := &RandomNode{Val: n.Val}
		seen[n] = c
		c.Next = clone(n.Next)
		c.Random = clone(n.Random)
		return c
	}
	return clone(head)
}
