def deep_copy_random_pointers(head):
    if head is None:
        return None
    seen = {}

    def clone(n):
        if n is None:
            return None
        c = seen.get(id(n))
        if c is not None:
            return c
        c = RandomNode(n.val)
        seen[id(n)] = c
        c.next = clone(n.next)
        c.random = clone(n.random)
