type DLLNode struct {
	Val        int
	Prev, Next *DLLNode
}

func deleteEveryKthNodeInDll(head *DLLNode, k int) *DLLNode {
	if head == nil || k <= 0 {
		return head
	}
	count := 0
	cur := head
	for cur != nil {
		count++
		cur = cur.Next
