func lastMenStanding(n, k int) int {
	if n == 1 {
		return 1
	}
	head := &ListNode{Val: 1}
	cur := head
	for i := 2; i <= n; i++ {
		cur.Next = &ListNode{Val: i}
		cur = cur.Next
	}
	cur.Next = head
	cur = head
	for cur.Next != cur {
		for i := 1; i < k; i++ {
			cur = cur.Next
		}
		cur.Next = cur.Next.Next
	}
	return cur.Val
}
