	for i := 0; i <= len(s); i++ {
		if i < len(s) && s[i] == '' '' {
			continue
		}
		if i < len(s) && s[i] >= ''0'' && s[i] <= ''9'' {
			num = num*10 + int(s[i]-''0'')
			continue
		}
		switch op {
		case ''+'':
			stack = append(stack, num)
		case ''-'':
			stack = append(stack, -num)
		case ''*'':
			stack[len(stack)-1] *= num
		case ''/'':
			stack[len(stack)-1] /= num
		}
		num = 0
		if i < len(s) {
			op = s[i]
		}
	}
	res := 0
	for _, v := range stack {
