class Solution {
    public long calculate(String s) {
        ArrayList<Long> stack = new ArrayList<>();
        long num = 0;
        char op = ''+'';
        int n = s.length();
        for (int i = 0; i <= n; i++) {
            if (i < n && s.charAt(i) == '' '') {
                continue;
            }
            if (i < n && s.charAt(i) >= ''0'' && s.charAt(i) <= ''9'') {
                num = num * 10 + (s.charAt(i) - ''0'');
                continue;
            }
            switch (op) {
                case ''+'':
                    stack.add(num);
                    break;
                case ''-'':
                    stack.add(-num);
                    break;
                case ''*'':
                    stack.set(stack.size() - 1, stack.get(stack.size() - 1) * num);
                    break;
                case ''/'':
                    stack.set(stack.size() - 1, stack.get(stack.size() - 1) / num);
                    break;
            }
            num = 0;
            if (i < n) {
                op = s.charAt(i);
            }
        }
        long res = 0;
        for (long v : stack) {
            res += v;
        }
        return res;
    }
}', false, 2),
