func convertStringToInteger(s string) int {
	i, n := 0, len(s)
	for i < n && s[i] == '' '' {
		i++
	}
	if i == n {
		return 0
	}
	sign := 1
	if s[i] == ''-'' {
		sign = -1
		i++
	} else if s[i] == ''+'' {
		i++
	}
	const maxInt = int(^uint(0) >> 1)
	const minInt = -maxInt - 1
	result := 0
	for i < n && s[i] >= ''0'' && s[i] <= ''9'' {
		digit := int(s[i] - ''0'')
		if sign == 1 && result > (maxInt-digit)/10 {
			return maxInt
		}
		if sign == -1 && result < (minInt+digit)/10 {
			return minInt
		}
		result = result*10 + digit
		i++
	}
	return sign * result
}
