func fibMemo(n int) int {
	if n <= 1 {
		return n
	}
	memo := map[int]int{}
	var dfs func(int) int
	dfs = func(k int) int {
		if k <= 1 {
			return k
		}
		if v, ok := memo[k]; ok {
