  ('prep-math-integer-to-english-words', 'go', 'solution.go', 'package main
import "strings"


func numberToWords(num int) string {
	if num == 0 {
		return "Zero"
	}
	below20 := []string{"", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten", "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"}
	tens := []string{"", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"}
	thousands := []string{"", "Thousand", "Million", "Billion"}
	var helper func(n int) string
	helper = func(n int) string {
		if n == 0 {
			return ""
		}
		if n < 20 {
			return below20[n]
		}
		if n < 100 {
			r := tens[n/10]
			if n%10 > 0 {
				r += " " + below20[n%10]
			}
			return r
		}
		r := below20[n/100] + " Hundred"
		if n%100 > 0 {
			r += " " + helper(n%100)
		}
		return r
	}
	var parts []string
	idx := 0
	for num > 0 {
		if num%1000 != 0 {
			s := helper(num % 1000)
			if thousands[idx] != "" {
				s += " " + thousands[idx]
			}
			parts = append([]string{s}, parts...)
		}
		num /= 1000
		idx++
	}
	return strings.Join(parts, " ")
}
', true, 0),
  ('prep-math-integer-to-english-words', 'python', 'solution.py', 'class Solution:
    def numberToWords(self, num: int) -> str:
        if num == 0:
            return "Zero"
        below20 = ["", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten", "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"]
        tens = ["", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"]
        thousands = ["", "Thousand", "Million", "Billion"]

        def helper(n: int) -> str:
            if n == 0:
                return ""
            if n < 20:
                return below20[n]
            if n < 100:
                r = tens[n // 10]
                if n % 10 > 0:
                    r += " " + below20[n % 10]
                return r
            r = below20[n // 100] + " Hundred"
            if n % 100 > 0:
                r += " " + helper(n % 100)
            return r

        parts = []
        idx = 0
        while num > 0:
            if num % 1000 != 0:
                s = helper(num % 1000)
                if thousands[idx] != "":
                    s += " " + thousands[idx]
                parts = [s] + parts
            num //= 1000
            idx += 1
        return " ".join(parts)', false, 1),
  ('prep-math-integer-to-english-words', 'java', 'Solution.java', 'import java.util.*;

class Solution {
    private static final String[] BELOW20 = {"", "One", "Two", "Three", "Four", "Five", "Six", "Seven", "Eight", "Nine", "Ten", "Eleven", "Twelve", "Thirteen", "Fourteen", "Fifteen", "Sixteen", "Seventeen", "Eighteen", "Nineteen"};
    private static final String[] TENS = {"", "", "Twenty", "Thirty", "Forty", "Fifty", "Sixty", "Seventy", "Eighty", "Ninety"};
    private static final String[] THOUSANDS = {"", "Thousand", "Million", "Billion"};

    private String helper(long n) {
        if (n == 0) {
            return "";
        }
        if (n < 20) {
            return BELOW20[(int) n];
        }
        if (n < 100) {
            String r = TENS[(int) (n / 10)];
            if (n % 10 > 0) {
                r += " " + BELOW20[(int) (n % 10)];
            }
            return r;
        }
        String r = BELOW20[(int) (n / 100)] + " Hundred";
        if (n % 100 > 0) {
            r += " " + helper(n % 100);
        }
        return r;
    }

    public String numberToWords(int num) {
        if (num == 0) {
            return "Zero";
        }
        long n = num;
        List<String> parts = new ArrayList<>();
        int idx = 0;
        while (n > 0) {
            if (n % 1000 != 0) {
                String s = helper(n % 1000);
                if (!THOUSANDS[idx].equals("")) {
                    s += " " + THOUSANDS[idx];
                }
                parts.add(0, s);
            }
            n /= 1000;
            idx++;
        }
        return String.join(" ", parts);
    }
}', false, 2),
