  ('prep-math-maximum-number-of-visible-points', 'go', 'solution.go', 'package main
import (
	"math"
	"sort"
)


func visiblePoints(points [][]int, angle int, location []int) int {
	same := 0
	var angles []float64
	for _, p := range points {
		if p[0] == location[0] && p[1] == location[1] {
			same++
		} else {
			a := math.Atan2(float64(p[1]-location[1]), float64(p[0]-location[0])) * 180 / math.Pi
			angles = append(angles, a)
		}
	}
	sort.Float64s(angles)
	n := len(angles)
	for i := 0; i < n; i++ {
		angles = append(angles, angles[i]+360)
	}
	res, j := 0, 0
	limit := float64(angle)
	for i := 0; i < len(angles); i++ {
		for j < len(angles) && angles[j]-angles[i] <= limit {
			j++
		}
		if j-i > res {
			res = j - i
		}
	}
	return res + same
}
', true, 0),
