func nextGreaterElement(n int) int {
	s := []byte(strconv.Itoa(n))
	k := len(s)
	i := k - 2
	for i >= 0 && s[i] >= s[i+1] {
		i--
	}
	if i < 0 {
		return -1
	}
	j := k - 1
	for s[j] <= s[i] {
		j--
	}
	s[i], s[j] = s[j], s[i]
	for l, r := i+1, k-1; l < r; l, r = l+1, r-1 {
		s[l], s[r] = s[r], s[l]
	}
	val, _ := strconv.Atoi(string(s))
	if val > math.MaxInt32 {
		return -1
	}
	return val
}
