    if i < 0:
        return -1
    j = k - 1
    while s[j] <= s[i]:
        j -= 1
    s[i], s[j] = s[j], s[i]
    l, r = i + 1, k - 1
    while l < r:
        s[l], s[r] = s[r], s[l]
