class Solution {
    public int nextGreaterElement(int n) {
        char[] s = Integer.toString(n).toCharArray();
        int k = s.length;
        int i = k - 2;
        while (i >= 0 && s[i] >= s[i + 1]) {
            i--;
        }
        if (i < 0) {
            return -1;
        }
        int j = k - 1;
        while (s[j] <= s[i]) {
            j--;
        }
        char tmp = s[i];
        s[i] = s[j];
        s[j] = tmp;
        for (int l = i + 1, r = k - 1; l < r; l++, r--) {
            char t2 = s[l];
            s[l] = s[r];
            s[r] = t2;
        }
        long val = Long.parseLong(new String(s));
        if (val > Integer.MAX_VALUE) {
            return -1;
        }
        return (int) val;
    }
