    static int seedrand(int x) {
        final int A = 48271;
        final int Q = 44488;
        final int R = 3399;
        int hi = x / Q;
        int lo = x % Q;
        x = A * lo - R * hi;
        if (x < 0) {
            x += INT32_MAX;
        }
        return x;
    }

    static final class RngSource {
        int tap;
        int feed;
        long[] vec = new long[RNG_LEN];

        void seed(long seed) {
            tap = 0;
            feed = RNG_LEN - RNG_TAP;

            seed = seed % INT32_MAX; // Java % truncates toward zero, matching Go
            if (seed < 0) {
                seed += INT32_MAX;
            }
            if (seed == 0) {
                seed = 89482311;
            }

            int x = (int) seed;
            for (int i = -20; i < RNG_LEN; i++) {
                x = seedrand(x);
                if (i >= 0) {
                    long u;
                    u = (long) x << 40;
                    x = seedrand(x);
                    u ^= (long) x << 20;
                    x = seedrand(x);
                    u ^= (long) x;
                    u ^= RNG_COOKED[i];
                    vec[i] = u;
                }
            }
        }

        long uint64() {
            tap--;
            if (tap < 0) {
                tap += RNG_LEN;
            }
            feed--;
            if (feed < 0) {
                feed += RNG_LEN;
            }
            long x = vec[feed] + vec[tap];
            vec[feed] = x;
            return x;
        }

        long int63() {
            return uint64() & RNG_MASK;
        }
    }

    static final class GoRand {
        final RngSource src;

        GoRand(RngSource src) {
            this.src = src;
        }

        long int63() {
            return src.int63();
        }

        int int31() {
            return (int) (int63() >>> 32);
        }

        int int31n(int n) {
            if (n <= 0) {
                throw new IllegalArgumentException("invalid argument to Int31n");
            }
            if ((n & (n - 1)) == 0) { // power of two, can mask
                return int31() & (n - 1);
            }
            int max = (int) ((1L << 31) - 1 - (1L << 31) % n);
            int v = int31();
            while (v > max) {
                v = int31();
            }
            return v % n;
        }

        long int63n(long n) {
            if (n <= 0) {
