    static int seedrand(int x) {
        final int A = 48271, Q = 44488, R = 3399;
        int hi = x / Q;
        int lo = x % Q;
        x = A * lo - R * hi;
        if (x < 0) {
            x += INT32_MAX;
        }
        return x;
    }

    static final class RngSource {
        int tap, feed;
        long[] vec = new long[RNG_LEN];

        RngSource(long seed) {
            seed(seed);
        }

        void seed(long seed) {
            tap = 0;
            feed = RNG_LEN - RNG_TAP;

            seed = seed % INT32_MAX;
            if (seed < 0) {
                seed += INT32_MAX;
            }
            if (seed == 0) {
                seed = 89482311;
            }

            int x = (int) seed;
            for (int i = -20; i < RNG_LEN; i++) {
                x = seedrand(x);
                if (i >= 0) {
                    long u = ((long) x) << 40;
                    x = seedrand(x);
                    u ^= ((long) x) << 20;
                    x = seedrand(x);
                    u ^= (long) x;
                    u ^= RNG_COOKED[i];
                    vec[i] = u;
                }
            }
        }

        long uint64() {
