def _to_int64(x):
    """Emulate Go''s 64-bit signed int wraparound (Go `int` is 64-bit)."""
    x &= MASK
    if x >= (1 << 63):
        x -= (1 << 64)
    return x


def reverse_number(n):
    neg = n < 0
    if neg:
        n = _to_int64(-n)
    rev = 0
    while n > 0:
        rev = _to_int64(rev * 10 + n % 10)
        n = _to_int64(n // 10)
    if neg:
        return _to_int64(-rev)
