func findDiagonalOrder(mat [][]int) []int {
	m, n := len(mat), len(mat[0])
	res := make([]int, m*n)
	r, c, d := 0, 0, 1
	for i := 0; i < m*n; i++ {
		res[i] = mat[r][c]
		if d == 1 {
			if c == n-1 {
				r++
				d = -1
			} else if r == 0 {
				c++
				d = -1
			} else {
				r--
				c++
			}
		} else {
			if r == m-1 {
				c++
				d = 1
			} else if c == 0 {
				r++
				d = 1
			} else {
				r++
				c--
			}
		}
	}
	return res
}
