        n = matrix[0].length;
        memo = new int[m][n];
        int res = 0;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                int v = dfs(matrix, i, j);
                if (v > res) res = v;
            }
        }
        return res;
    }

    private int dfs(int[][] matrix, int r, int c) {
        if (memo[r][c] > 0) return memo[r][c];
        int mx = 1;
