    public long maxRegion(int[][] mat) {
        if (mat.length == 0) {
            return 0;
        }
        m = mat.length;
        n = mat[0].length;
        long best = 0;
        for (int i = 0; i < m; i++) {
            for (int j = 0; j < n; j++) {
                if (mat[i][j] == 1) {
                    long a = dfs(mat, i, j);
                    if (a > best) {
                        best = a;
                    }
                }
            }
        }
        return best;
    }

    private long dfs(int[][] mat, int i, int j) {
        if (i < 0 || j < 0 || i >= m || j >= n || mat[i][j] != 1) {
            return 0;
        }
        mat[i][j] = 0;
        long area = 1;
        for (int[] d : DIRS) {
