func minDist1D(a []int) int {
	sort.Ints(a)
	lo, hi := 0, len(a)-1
	dist := 0
	for lo < hi {
		mn := a[lo]
		if a[hi] < mn {
			mn = a[hi]
		}
		dist += mn * (hi - lo)
		if a[lo] == mn {
			lo++
		}
		if a[hi] == mn {
			hi--
		}
	}
	return dist
}

func minDistanceOfMeetingPoint(grid [][]int) int {
	var rows, cols []int
	for r := range grid {
		for c, v := range grid[r] {
			if v == 1 {
				rows = append(rows, r)
				cols = append(cols, c)
			}
		}
	}
	return minDist1D(rows) + minDist1D(cols)
}
