func wordSearchOnBoard(board [][]byte, word string) bool {
	m, n := len(board), len(board[0])
	visited := make([][]bool, m)
	for i := range visited {
		visited[i] = make([]bool, n)
	}
	dirs := [][2]int{{0, 1}, {1, 0}, {0, -1}, {-1, 0}}
	var dfs func(int, int, int) bool
	dfs = func(i, j, idx int) bool {
		if idx == len(word) {
			return true
		}
		if i < 0 || j < 0 || i >= m || j >= n || visited[i][j] || board[i][j] != word[idx] {
			return false
		}
		visited[i][j] = true
		for _, d := range dirs {
			if dfs(i+d[0], j+d[1], idx+1) {
				return true
			}
		}
		visited[i][j] = false
		return false
	}
	for i := 0; i < m; i++ {
		for j := 0; j < n; j++ {
			if dfs(i, j, 0) {
				return true
			}
		}
	}
	return false
}
