class Solution {
    public long subarraySum(long[] nums, long k) {
        Map<Long, Long> prefixMap = new HashMap<>();
        prefixMap.put(0L, 1L);
        long sum = 0, cnt = 0;
        for (long num : nums) {
            sum += num;
            Long c = prefixMap.get(sum - k);
            if (c != null) {
                cnt += c;
            }
            prefixMap.merge(sum, 1L, Long::sum);
