func minWindow(s string, t string) string {
	if len(s) < len(t) {
		return ""
	}
	var freq [128]int
	for i := 0; i < len(t); i++ {
		freq[t[i]]++
	}
	need := len(t)
	minLen, minStart := len(s)+1, 0
	l := 0
	for r := 0; r < len(s); r++ {
		if freq[s[r]] > 0 {
			need--
		}
		freq[s[r]]--
		for need == 0 {
			if r-l+1 < minLen {
				minLen = r - l + 1
				minStart = l
			}
			freq[s[l]]++
			if freq[s[l]] > 0 {
				need++
			}
			l++
		}
	}
	if minLen > len(s) {
		return ""
	}
	return s[minStart : minStart+minLen]
}
