import java.util.*;

class Solution {
    public String minWindow(String s, String t) {
        byte[] sb = s.getBytes(StandardCharsets.UTF_8);
        byte[] tb = t.getBytes(StandardCharsets.UTF_8);
        if (sb.length < tb.length) {
            return "";
        }
        int[] freq = new int[128];
        for (int i = 0; i < tb.length; i++) {
            freq[tb[i] & 0xFF]++;
        }
        int need = tb.length;
        int minLen = sb.length + 1, minStart = 0;
        int l = 0;
        for (int r = 0; r < sb.length; r++) {
            if (freq[sb[r] & 0xFF] > 0) {
                need--;
            }
            freq[sb[r] & 0xFF]--;
            while (need == 0) {
                if (r - l + 1 < minLen) {
                    minLen = r - l + 1;
                    minStart = l;
                }
                freq[sb[l] & 0xFF]++;
                if (freq[sb[l] & 0xFF] > 0) {
                    need++;
                }
                l++;
            }
        }
        if (minLen > sb.length) {
            return "";
        }
        return new String(sb, minStart, minLen, StandardCharsets.UTF_8);
    }
