    if sum1 > sum2:
        nums1, nums2 = nums2, nums1
        sum1, sum2 = sum2, sum1
    diff = sum2 - sum1
    if diff == 0:
        return 0
    contrib = [0] * 6
    for x in nums1:
        contrib[6 - x] += 1
    for x in nums2:
        contrib[x - 1] += 1
    ops = 0
    c = 5
    while c >= 1 and diff > 0:
        take = contrib[c]
        need = (diff + c - 1) // c
        if take > need:
            take = need
        ops += take
        diff -= take * c
        c -= 1
    if diff > 0:
