class Solution {
    public int maxChunksToSorted(long[] arr) {
        Deque<Long> stack = new ArrayDeque<>();
        for (long val : arr) {
            long mx = val;
            while (!stack.isEmpty() && stack.peekLast() > val) {
                long top = stack.pollLast();
                if (top > mx) {
                    mx = top;
                }
            }
            stack.addLast(mx);
        }
        return stack.size();
    }
}', false, 2),
