        for (int i = 0; i < b.length; i++) {
            freq[(b[i] & 0xFF) - ''a'']++;
        }
        Arrays.sort(freq);
        int dels = 0;
        Set<Integer> used = new HashSet<>();
        for (int i = 25; i >= 0; i--) {
            while (freq[i] > 0 && used.contains(freq[i])) {
