  ('prep-sorting-sort-integers-by-the-power-value', 'go', 'solution.go', 'package main
import "sort"


func getKth(lo int, hi int, k int) int {
	memo := map[int]int{}
	var power func(n int) int
	power = func(n int) int {
		if n == 1 {
			return 0
		}
		if v, ok := memo[n]; ok {
			return v
		}
		var res int
		if n%2 == 0 {
			res = 1 + power(n/2)
		} else {
			res = 1 + power(3*n+1)
		}
		memo[n] = res
		return res
	}
	nums := make([]int, hi-lo+1)
	for i := lo; i <= hi; i++ {
		nums[i-lo] = i
	}
	sort.Slice(nums, func(i, j int) bool {
