        }
        List<Long> res = new ArrayList<>();
        for (int i = buckets.size() - 1; i >= 0 && res.size() < k; i--) {
            for (long num : buckets.get(i)) {
                res.add(num);
                if (res.size() == k) {
                    return toArray(res);
                }
            }
        }
        return toArray(res);
