func applyInfix(a, b int64, op byte) int64 {
	switch op {
	case ''+'':
		return a + b
	case ''-'':
		return a - b
	case ''*'':
		return a * b
	case ''/'':
		return a / b
	}
	return 0
}

func opPrec(op byte) int {
	if op == ''+'' || op == ''-'' {
		return 1
	}
	return 2
}

func calculateInfix(exp string) int64 {
	var nums []int64
	var ops []byte
	applyTop := func() {
		op := ops[len(ops)-1]
		ops = ops[:len(ops)-1]
		b := nums[len(nums)-1]
		a := nums[len(nums)-2]
		nums = nums[:len(nums)-2]
		nums = append(nums, applyInfix(a, b, op))
	}
	i, n := 0, len(exp)
	for i < n {
		c := exp[i]
		if c == '' '' {
			i++
			continue
		}
		if c >= ''0'' && c <= ''9'' {
			var val int64
			for i < n && exp[i] >= ''0'' && exp[i] <= ''9'' {
				val = val*10 + int64(exp[i]-''0'')
				i++
			}
			nums = append(nums, val)
			continue
		}
		for len(ops) > 0 && opPrec(ops[len(ops)-1]) >= opPrec(c) {
			applyTop()
		}
		ops = append(ops, c)
		i++
	}
	for len(ops) > 0 {
		applyTop()
	}
	return nums[0]
}
