  ('prep-stacks-queues-calculate-infix', 'python', 'solution.py', 'MASK = (1 << 64) - 1


def _wrap64(x):
    x &= MASK
    if x >= (1 << 63):
        x -= (1 << 64)
    return x


def apply_infix(a, b, op):
    if op == ord(''+''):
        return _wrap64(a + b)
    if op == ord(''-''):
        return _wrap64(a - b)
    if op == ord(''*''):
        return _wrap64(a * b)
    if op == ord(''/''):
        # Go int64 division truncates toward zero
        q = abs(a) // abs(b)
        if (a < 0) != (b < 0):
            q = -q
        return _wrap64(q)
    return 0


def op_prec(op):
    if op == ord(''+'') or op == ord(''-''):
        return 1
    return 2


def calculate_infix(exp):
    b = exp.encode(''utf-8'')
    nums = []
    ops = []

    def apply_top():
        op = ops.pop()
        y = nums.pop()
        x = nums.pop()
        nums.append(apply_infix(x, y, op))

    i, n = 0, len(b)
    while i < n:
        c = b[i]
        if c == ord('' ''):
            i += 1
            continue
        if ord(''0'') <= c <= ord(''9''):
            val = 0
            while i < n and ord(''0'') <= b[i] <= ord(''9''):
                val = _wrap64(val * 10 + (b[i] - ord(''0'')))
                i += 1
            nums.append(val)
            continue
        while ops and op_prec(ops[-1]) >= op_prec(c):
            apply_top()
        ops.append(c)
        i += 1
    while ops:
        apply_top()
    return nums[0]', false, 1),
