def _to_i64(x):
    x &= MASK
    if x >= (1 << 63):
        x -= (1 << 64)
    return x


def _trunc_div(a, b):
    q = abs(a) // abs(b)
    if (a < 0) != (b < 0):
        q = -q
    return q


def apply_op(a, b, op):
    if op == "+":
        return _to_i64(a + b)
    if op == "-":
        return _to_i64(a - b)
    if op == "*":
        return _to_i64(a * b)
    if op == "/":
        return _to_i64(_trunc_div(a, b))
    return 0


def calculate_postfix(tokens):
    stack = []
    for tok in tokens:
        if tok in ("+", "-", "*", "/"):
            b = stack[-1]
            a = stack[-2]
            del stack[-2:]
            stack.append(apply_op(a, b, tok))
        else:
            v = 0
            data = tok.encode("utf-8")
