func decodeString(s string) string {
	var cntStack []int
	var strStack []string
	cur := ""
	num := 0
	for i := 0; i < len(s); i++ {
		c := s[i]
		if c >= ''0'' && c <= ''9'' {
			num = num*10 + int(c-''0'')
		} else if c == ''['' {
			cntStack = append(cntStack, num)
			strStack = append(strStack, cur)
			num, cur = 0, ""
		} else if c == '']'' {
			k := cntStack[len(cntStack)-1]
			cntStack = cntStack[:len(cntStack)-1]
			prev := strStack[len(strStack)-1]
			strStack = strStack[:len(strStack)-1]
			cur = prev + strings.Repeat(cur, k)
		} else {
			cur += string(c)
		}
	}
	return cur
