class QueueWithMax:
    def __init__(self):
        self.queue = deque()
        self.max_dq = deque()

    def enqueue(self, val):
        self.queue.append(val)
        while self.max_dq and self.max_dq[-1] < val:
            self.max_dq.pop()
        self.max_dq.append(val)

    def dequeue(self):
        if not self.queue:
            return 0
        v = self.queue.popleft()
        if self.max_dq and self.max_dq[0] == v:
            self.max_dq.popleft()
        return v

