func prec(c rune) int {
	switch c {
	case ''+'', ''-'':
		return 1
	case ''*'', ''/'':
		return 2
	default:
		return 0
	}
}

func infixToPostfix(exp string) string {
	var out []byte
	var ops []rune
	for _, c := range exp {
		if c == '' '' {
			continue
		}
		if c >= ''0'' && c <= ''9'' {
			out = append(out, byte(c))
		} else {
			for len(ops) > 0 && prec(ops[len(ops)-1]) >= prec(c) {
				out = append(out, byte(ops[len(ops)-1]))
				ops = ops[:len(ops)-1]
			}
			ops = append(ops, c)
		}
	}
	for len(ops) > 0 {
		out = append(out, byte(ops[len(ops)-1]))
		ops = ops[:len(ops)-1]
	}
	return string(out)
}
