func isOp(c byte) bool {
	return c == ''+'' || c == ''-'' || c == ''*'' || c == ''/''
}

func prefixToPostfix(exp string) string {
	var stack []string
	for i := len(exp) - 1; i >= 0; i-- {
		c := exp[i]
		if c == '' '' {
			continue
		}
		if isOp(c) {
			a := stack[len(stack)-1]
			b := stack[len(stack)-2]
			stack = stack[:len(stack)-2]
			stack = append(stack, a+b+string(c))
		} else {
			stack = append(stack, string(c))
		}
	}
	return stack[len(stack)-1]
}
