func validateParentheses(str string) bool {
	pairs := map[rune]rune{'')'': ''('', '']'': ''['', ''}'': ''{''}
	var stack []rune
	for _, c := range str {
		if c == ''('' || c == ''['' || c == ''{'' {
			stack = append(stack, c)
		} else if open, ok := pairs[c]; ok {
			if len(stack) == 0 || stack[len(stack)-1] != open {
				return false
			}
			stack = stack[:len(stack)-1]
		}
	}
	return len(stack) == 0
}
