func addSpacesAroundParenthesesIn(s string) string {
	var out strings.Builder
	prevSpace := true
	for i := 0; i < len(s); i++ {
		ch := s[i]
		if ch == ''('' || ch == '')'' {
			if !prevSpace {
				out.WriteByte('' '')
			}
			out.WriteByte(ch)
			out.WriteByte('' '')
			prevSpace = true
		} else if ch == '' '' {
			if !prevSpace {
				out.WriteByte('' '')
			}
			prevSpace = true
		} else {
			out.WriteByte(ch)
			prevSpace = false
		}
	}
	return strings.TrimSpace(out.String())
}
