type treeNode struct {
	val   int
	left  *treeNode
	right *treeNode
}

type binaryTreeInOrderIterator struct {
	stack []*treeNode
}

func newBinaryTreeInOrderIterator(root *treeNode) *binaryTreeInOrderIterator {
	it := &binaryTreeInOrderIterator{}
	for node := root; node != nil; node = node.left {
		it.stack = append(it.stack, node)
	}
	return it
}

func (it *binaryTreeInOrderIterator) hasNext() bool {
	return len(it.stack) > 0
}

func (it *binaryTreeInOrderIterator) next() int {
	node := it.stack[len(it.stack)-1]
	it.stack = it.stack[:len(it.stack)-1]
	val := node.val
	for node = node.right; node != nil; node = node.left {
		it.stack = append(it.stack, node)
	}
	return val
}
