type palindromeStream struct {
	back []byte
}

func newPalindromeStream() *palindromeStream {
	return &palindromeStream{}
}

func (ps *palindromeStream) letter(ch byte) bool {
	n := len(ps.back)
	if n > 0 && ps.back[n-1] == ch {
		ps.back = ps.back[:n-1]
		return true
	}
	ps.back = append(ps.back, ch)
	return false
}

func checkPalindromeInStream(chars []byte) bool {
	ps := newPalindromeStream()
	ok := true
	for _, ch := range chars {
		if !ps.letter(ch) {
			ok = false
		}
	}
	return ok && len(ps.back) == 0
}
