import (
	"os"
)


func reverseContentOfFileInPlace(path string) error {
	data, err := os.ReadFile(path)
	if err != nil {
		return err
	}
	for i, j := 0, len(data)-1; i < j; i, j = i+1, j-1 {
		data[i], data[j] = data[j], data[i]
	}
	return os.WriteFile(path, data, 0644)
}
