  ('prep-strings-custom-sort-string', 'go', 'solution.go', 'package main
func customSortString(order string, s string) string {
	cnt := [26]int{}
	for _, c := range s {
		cnt[c-''a'']++
	}
	var res []byte
	for _, c := range order {
		for cnt[c-''a''] > 0 {
			res = append(res, byte(c))
			cnt[c-''a'']--
		}
	}
	for i := 0; i < 26; i++ {
		for cnt[i] > 0 {
			res = append(res, byte(''a''+i))
			cnt[i]--
		}
	}
	return string(res)
}
