func findAnagramSubstringIndices(s, p string) []int {
	if len(p) > len(s) {
		return nil
	}
	diff := make([]int, 26)
	for i := 0; i < len(p); i++ {
		diff[p[i]-''a'']++
	}
	out := []int{}
	for i := 0; i < len(s); i++ {
		diff[s[i]-''a'']--
		if i >= len(p) {
			diff[s[i-len(p)]-''a'']++
		}
		if i >= len(p)-1 {
			ok := true
			for _, d := range diff {
				if d != 0 {
					ok = false
					break
				}
			}
			if ok {
				out = append(out, i-len(p)+1)
			}
		}
	}
	return out
}
