    l, r = 0, len(b) - 1
    while l < r:
        while l < r and not _is_alnum(b[l]):
            l += 1
        while l < r and not _is_alnum(b[r]):
            r -= 1
        if _to_lower(b[l]) != _to_lower(b[r]):
            return False
        l += 1
        r -= 1
    return True


def _is_alnum(c: int) -> bool:
    return (
        (ord(''a'') <= c <= ord(''z''))
        or (ord(''A'') <= c <= ord(''Z''))
        or (ord(''0'') <= c <= ord(''9''))
    )


def _to_lower(c: int) -> int:
    if ord(''A'') <= c <= ord(''Z''):
        return c - ord(''A'') + ord(''a'')
