        for (int k = 0; k < strs.length; k++) {
            encoded[k] = strs[k].getBytes(StandardCharsets.UTF_8);
        }
        byte[] first = encoded[0];
        for (int i = 0; i < first.length; i++) {
            byte c = first[i];
