  ('prep-strings-min-insertions-to-form-palin', 'go', 'solution.go', 'package main
func minInsertionsToFormPalin(s string) int {
	n := len(s)
	if n == 0 {
		return 0
	}
	dp := make([][]int, n)
	for i := range dp {
		dp[i] = make([]int, n)
		dp[i][i] = 1
	}
	for l := n - 2; l >= 0; l-- {
		for r := l + 1; r < n; r++ {
			if s[l] == s[r] {
				dp[l][r] = dp[l+1][r-1] + 2
			} else {
				dp[l][r] = max(dp[l+1][r], dp[l][r-1])
			}
		}
	}
	return n - dp[0][n-1]
}
