class Solution {
    public String minRemoveToMakeValid(String s) {
        byte[] buf = s.getBytes(StandardCharsets.UTF_8);
        List<Integer> stack = new ArrayList<>();
        for (int i = 0; i < buf.length; i++) {
            if (buf[i] == ''('') {
                stack.add(i);
            } else if (buf[i] == '')'') {
                if (!stack.isEmpty()) {
                    stack.remove(stack.size() - 1);
                } else {
                    buf[i] = ''*'';
