	idx  int
}

func numMatchingSubseq(s string, words []string) int {
	buckets := map[byte][]wordNode{}
	for _, w := range words {
		buckets[w[0]] = append(buckets[w[0]], wordNode{w, 0})
	}
	cnt := 0
	for i := 0; i < len(s); i++ {
		nodes := buckets[s[i]]
		delete(buckets, s[i])
		for _, nd := range nodes {
			nd.idx++
			if nd.idx == len(nd.word) {
				cnt++
			} else {
				buckets[nd.word[nd.idx]] = append(buckets[nd.word[nd.idx]], nd)
			}
		}
	}
	return cnt
}
