func runLengthEncoding(s string) string {
	if len(s) == 0 {
		return ""
	}
	var b []byte
	run, c := 1, s[0]
	for i := 1; i < len(s); i++ {
		if s[i] == c {
			run++
		} else {
			b = append(b, c)
			b = append(b, byte(''0''+run))
			c = s[i]
			run = 1
