    data = s.encode(''utf-8'')
    if len(data) == 0:
        return ""
    b = bytearray()
    run = 1
    c = data[0]
    for i in range(1, len(data)):
        if data[i] == c:
            run += 1
        else:
            b.append(c)
            b.append((ord(''0'') + run) & 0xFF)
            c = data[i]
            run = 1
    b.append(c)
    b.append((ord(''0'') + run) & 0xFF)
    # Go returns string(b): the raw bytes reinterpreted as a string. We decode as
