func shortestSubarrayContainsAll(nums []int, target int) int {
	sum, l, best := 0, 0, int(^uint(0)>>1)
	for r := 0; r < len(nums); r++ {
		sum += nums[r]
		for sum >= target {
			if r-l+1 < best {
				best = r - l + 1
			}
			sum -= nums[l]
			l++
		}
	}
	if best == int(^uint(0)>>1) {
		return 0
	}
	return best
}
