  ('prep-strings-word-wrap', 'python', 'solution.py', 'def word_wrap(words, max_width):
    n = len(words)
    if n == 0:
        return None
    # Go indexes strings by BYTE; len(word) in Go = UTF-8 byte length.
    blen = [len(w.encode(''utf-8'')) for w in words]
    INT_MAX = (1 << 63) - 1
    dp = [0] * (n + 1)
    nxt = [0] * n
    for i in range(n - 1, -1, -1):
        dp[i] = INT_MAX
        length = 0
        for j in range(i, n):
            if j > i:
                length += 1
            length += blen[j]
            if length > max_width:
                break
            cost = 0
            if j < n - 1:
                rem = max_width - length
                cost = rem * rem + dp[j + 1]
            if cost < dp[i]:
                dp[i] = cost
                nxt[i] = j + 1
    out = []
    i = 0
    while i < n:
        j = nxt[i] - 1
        line = join_words(words[i:j + 1])
        out.append(line)
        i = nxt[i]
    return out


def join_words(words):
    if len(words) == 0:
        return ""
    out = words[0]
    for i in range(1, len(words)):
        out += " " + words[i]
