  ('prep-strings-word-wrap', 'java', 'Solution.java', 'import java.util.*;
import java.nio.charset.StandardCharsets;

class Solution {
    static List<String> wordWrap(String[] words, int maxWidth) {
        int n = words.length;
        if (n == 0) {
            return null;
        }
        int[] blen = new int[n];
        for (int k = 0; k < n; k++) {
            blen[k] = words[k].getBytes(StandardCharsets.UTF_8).length;
        }
        long[] dp = new long[n + 1];
        int[] next = new int[n];
        for (int i = n - 1; i >= 0; i--) {
            dp[i] = Long.MAX_VALUE;
            long length = 0;
            for (int j = i; j < n; j++) {
                if (j > i) {
                    length++;
                }
                length += blen[j];
                if (length > maxWidth) {
                    break;
                }
                long cost = 0;
                if (j < n - 1) {
                    long rem = maxWidth - length;
                    cost = rem * rem + dp[j + 1];
                }
                if (cost < dp[i]) {
                    dp[i] = cost;
                    next[i] = j + 1;
                }
            }
        }
        List<String> out = new ArrayList<>();
        int i = 0;
        while (i < n) {
            int j = next[i] - 1;
            String line = joinWords(Arrays.copyOfRange(words, i, j + 1));
            out.add(line);
            i = next[i];
        }
        return out;
    }

    static String joinWords(String[] words) {
        if (words.length == 0) {
            return "";
        }
        String out = words[0];
        for (int i = 1; i < words.length; i++) {
            out += " " + words[i];
        }
        return out;
    }
}', false, 2),
  ('prep-trees-binary-search-tree-iterator', 'go', 'solution.go', 'package main
type TreeNode struct {
	Val   int
	Left  *TreeNode
	Right *TreeNode
}

type BSTIterator struct {
	stack []*TreeNode
}

func Constructor(root *TreeNode) BSTIterator {
	it := BSTIterator{}
	it.pushLeft(root)
	return it
}

func (it *BSTIterator) pushLeft(node *TreeNode) {
	for node != nil {
		it.stack = append(it.stack, node)
		node = node.Left
	}
}

func (it *BSTIterator) Next() int {
	top := it.stack[len(it.stack)-1]
	it.stack = it.stack[:len(it.stack)-1]
	it.pushLeft(top.Right)
	return top.Val
}

