func verticalOrder(root *TreeNode) [][]int {
	if root == nil {
		return nil
	}
	cols := map[int][]int{}
	minC, maxC := 0, 0
	type item struct {
		node *TreeNode
		col  int
	}
	q := []item{{root, 0}}
	for len(q) > 0 {
		cur := q[0]
		q = q[1:]
		cols[cur.col] = append(cols[cur.col], cur.node.Val)
		if cur.col < minC {
			minC = cur.col
		}
		if cur.col > maxC {
			maxC = cur.col
		}
		if cur.node.Left != nil {
			q = append(q, item{cur.node.Left, cur.col - 1})
		}
		if cur.node.Right != nil {
			q = append(q, item{cur.node.Right, cur.col + 1})
		}
	}
	res := make([][]int, 0, maxC-minC+1)
	for c := minC; c <= maxC; c++ {
		res = append(res, cols[c])
	}
	return res
}
