	var res [][]int
	q := []*TreeNode{root}
	ltr := true
	for len(q) > 0 {
		sz := len(q)
		level := make([]int, sz)
		for i := 0; i < sz; i++ {
			node := q[0]
			q = q[1:]
			idx := i
			if !ltr {
				idx = sz - 1 - i
			}
			level[idx] = node.Val
			if node.Left != nil {
				q = append(q, node.Left)
			}
			if node.Right != nil {
				q = append(q, node.Right)
			}
		}
		res = append(res, level)
		ltr = !ltr
	}
	return res
}
