func findLowestCommonAncestor(root, a, b *NaryNode) *NaryNode {
	if root == nil {
		return nil
	}
	if root == a || root == b {
		return root
	}
	var found *NaryNode
	count := 0
	for _, child := range root.Children {
		lca := findLowestCommonAncestor(child, a, b)
		if lca != nil {
			count++
			found = lca
		}
	}
	if count >= 2 {
		return root
	}
	return found
}

func levelDistance(root, target *NaryNode) int {
	if root == target {
		return 0
	}
	level := 0
	frontier := root.Children
	for len(frontier) > 0 {
		level++
		next := make([]*NaryNode, 0)
		for _, node := range frontier {
			if node == target {
				return level
			}
			next = append(next, node.Children...)
		}
		frontier = next
	}
	return -1
}

func findDistanceOfTwoNodes(root, a, b *NaryNode) int {
	lca := findLowestCommonAncestor(root, a, b)
	return levelDistance(lca, a) + levelDistance(lca, b)
}
