func findLeaves(root *TreeNode) [][]int {
	var res [][]int
	var dfs func(node *TreeNode) int
	dfs = func(node *TreeNode) int {
		if node == nil {
			return -1
		}
		h := dfs(node.Left)
		if r := dfs(node.Right); r > h {
			h = r
		}
		h++
		if h == len(res) {
			res = append(res, []int{})
