func getHeight(root *NaryNode) int {
	if root == nil {
		return -1
	}
	maxChild := -1
	for _, child := range root.Children {
		if h := getHeight(child); h > maxChild {
			maxChild = h
		}
	}
	return maxChild + 1
}

func getDiameter(root *NaryNode) int {
	if root == nil {
		return 0
	}
	max1, max2 := -1, -1
	for _, child := range root.Children {
		h := getHeight(child)
		if h > max1 {
			max2 = max1
			max1 = h
		} else if h > max2 {
			max2 = h
		}
	}
	diameter := 0
	if max1 >= 0 && max2 >= 0 {
		diameter = max1 + max2 + 2
	} else if max1 >= 0 {
		diameter = max1 + 1
	}
	for _, child := range root.Children {
		if d := getDiameter(child); d > diameter {
			diameter = d
		}
	}
	return diameter
}
