  ('prep-trees-lowest-common-ancestor-of-a-binary-tree', 'go', 'variants/iterative.go', 'package main
func lowestCommonAncestorIter(root, p, q *TreeNode) *TreeNode {
	if root == nil {
		return nil
	}
	parent := map[*TreeNode]*TreeNode{root: nil}
	seen := map[*TreeNode]bool{}
	stack := []*TreeNode{root}
	for len(stack) > 0 || !seen[p] || !seen[q] {
		node := stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		if node == p || node == q {
			seen[node] = true
		}
		if node.Right != nil {
			parent[node.Right] = node
			stack = append(stack, node.Right)
		}
		if node.Left != nil {
			parent[node.Left] = node
			stack = append(stack, node.Left)
		}
	}
	ancestors := map[*TreeNode]bool{}
	for p != nil {
		ancestors[p] = true
		p = parent[p]
	}
	for !ancestors[q] {
		q = parent[q]
	}
	return q
}
