	Children []*NaryNode
}

func naryTreeTraversalIteratively(root *NaryNode) []int {
	return preOrderIter(root)
}

func preOrderIter(root *NaryNode) []int {
	if root == nil {
		return nil
	}
	res := make([]int, 0)
	stack := []*NaryNode{root}
	for len(stack) > 0 {
		curr := stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		res = append(res, curr.Val)
		for i := len(curr.Children) - 1; i >= 0; i-- {
			stack = append(stack, curr.Children[i])
		}
	}
	return res
}

func postOrderIter(root *NaryNode) []int {
	if root == nil {
		return nil
	}
	res := make([]int, 0)
	stack := []*NaryNode{root}
	for len(stack) > 0 {
		curr := stack[len(stack)-1]
		stack = stack[:len(stack)-1]
		res = append([]int{curr.Val}, res...)
		for _, child := range curr.Children {
			stack = append(stack, child)
		}
	}
	return res
}
