type TreeNode struct {
	Val         int
	Left, Right *TreeNode
}

func pathSumToK(root *TreeNode, k int) int {
	cnt := map[int]int{0: 1}
	ans := 0
	var dfs func(*TreeNode, int)
	dfs = func(node *TreeNode, sum int) {
		if node == nil {
			return
		}
		sum += node.Val
		ans += cnt[sum-k]
		cnt[sum]++
		dfs(node.Left, sum)
		dfs(node.Right, sum)
		cnt[sum]--
	}
	dfs(root, 0)
	return ans
}
