	Left, Right *TreeNode
	Next        *TreeNode
}

func populateNextPointersToRight(root *TreeNode) *TreeNode {
	if root == nil {
		return nil
	}
	leftmost := root
	for leftmost.Left != nil {
		cur := leftmost
		var nextLeft *TreeNode
		for cur != nil {
			if cur.Left != nil {
				cur.Left.Next = cur.Right
				if cur.Next != nil {
					cur.Right.Next = cur.Next.Left
				}
				if nextLeft == nil {
					nextLeft = cur.Left
				}
			}
			cur = cur.Next
		}
		leftmost = nextLeft
	}
	return root
}
