def populate_next_pointers_to_right(root: "Optional[TreeNode]") -> "Optional[TreeNode]":
    if root is None:
        return None
    leftmost = root
    while leftmost.left is not None:
        cur = leftmost
        next_left = None
        while cur is not None:
            if cur.left is not None:
                cur.left.next = cur.right
                if cur.next is not None:
