class TreeNode:
    def __init__(self, val: int = 0, left: "Optional[TreeNode]" = None, right: "Optional[TreeNode]" = None):
        self.val = val
        self.left = left
        self.right = right


def serializeAndDeserialize(root: Optional[TreeNode]) -> Tuple[str, Optional[TreeNode]]:
    if root is None:
        return "", None
    parts: List[str] = []
    q: List[Optional[TreeNode]] = [root]
    head = 0
    while head < len(q):
        node = q[head]
        head += 1
        if node is None:
            parts.append("#")
            continue
        parts.append(_itoa(node.val))
        q.append(node.left)
        q.append(node.right)
    data = _join_comma(parts)
    return data, _deserialize_tree(data)


def _itoa(n: int) -> str:
    if n == 0:
        return "0"
    neg = False
    if n < 0:
        neg = True
        n = -n
    d: List[int] = []
    while n > 0:
        d.append(ord(''0'') + n % 10)
        n //= 10
    if neg:
        d.append(ord(''-''))
    d.reverse()
    return bytes(d).decode(''ascii'')


def _join_comma(parts: List[str]) -> str:
    if len(parts) == 0:
        return ""
    out = parts[0]
    for i in range(1, len(parts)):
        out += "," + parts[i]
    return out


def _split_comma(s: str) -> List[str]:
    b = s.encode(''utf-8'')
    out: List[str] = []
    start = 0
    for i in range(len(b) + 1):
        if i == len(b) or b[i] == ord('',''):
            out.append(b[start:i].decode(''utf-8''))
            start = i + 1
    return out


def _atoi(s: str) -> int:
    if s == "#" or s == "":
        return 0
    b = s.encode(''utf-8'')
    neg = False
    i = 0
    if b[0] == ord(''-''):
        neg = True
        i = 1
    n = 0
    while i < len(b):
        n = n * 10 + (b[i] - ord(''0''))
        i += 1
    if neg:
        return -n
    return n


def _deserialize_tree(data: str) -> Optional[TreeNode]:
    if data == "":
        return None
    vals = _split_comma(data)
    idx = [0]

    def build() -> Optional[TreeNode]:
        if idx[0] >= len(vals) or vals[idx[0]] == "#":
            idx[0] += 1
            return None
        node = TreeNode(_atoi(vals[idx[0]]))
        idx[0] += 1
        node.left = build()
        node.right = build()
        return node

