import (
	"fmt"
	"sync"
)

// producer sends n values then closes; direction type enforces send-only.
func producer(out chan<- int, n int) {
	for i := 0; i < n; i++ {
		out <- i
	}
	close(out)
}

// merge fans in two receive-only channels using comma-ok to detect close.
func merge(a, b <-chan int) <-chan int {
	out := make(chan int)
	var wg sync.WaitGroup
	drain := func(c <-chan int) {
		defer wg.Done()
		for {
			v, ok := <-c
			if !ok {
				return // closed channel: ok is false, v is zero value
			}
			out <- v
		}
	}
	wg.Add(2)
	go drain(a)
	go drain(b)
	go func() {
		wg.Wait()
		close(out)
	}()
	return out
}

func main() {
	a := make(chan int)    // unbuffered: send blocks until received
	b := make(chan int, 3) // buffered: send blocks only when full
	go producer(a, 3)
	go producer(b, 3)

	sum := 0
	for v := range merge(a, b) { // range stops when out is closed
		sum += v
	}
	fmt.Println(sum)
}', true, 0),
  ('go-conc-select', 'go', 'main.go', 'package main

import (
	"context"
	"errors"
	"fmt"
	"time"
)

// merge fans two input streams into out until both close, honoring ctx.
// Closed inputs are set to nil so their select case is disabled forever.
func merge(ctx context.Context, a, b <-chan int) []int {
	var got []int
	for a != nil || b != nil {
		select {
		case <-ctx.Done():
			return got
		case v, ok := <-a:
			if !ok {
				a = nil // disable this case, don''t spin on the closed channel
				continue
			}
			got = append(got, v)
		case v, ok := <-b:
			if !ok {
				b = nil
				continue
			}
			got = append(got, v)
		}
	}
	return got
}

// trySend is a non-blocking send using default.
func trySend(ch chan<- int, v int) bool {
	select {
	case ch <- v:
		return true
	default:
		return false
	}
}

func main() {
	a := make(chan int, 2)
	b := make(chan int, 2)
	a <- 1
	b <- 2
	close(a)
	close(b)

	ctx, cancel := context.WithTimeout(context.Background(), 50*time.Millisecond)
	defer cancel()

	res := merge(ctx, a, b)
	fmt.Println("merged count:", len(res))

	full := make(chan int) // unbuffered, no receiver
	fmt.Println("trySend ok:", trySend(full, 99))

	if errors.Is(ctx.Err(), context.DeadlineExceeded) {
		fmt.Println("deadline hit")
	}
}
