// worker fans results into out but honors ctx so it never leaks if the
// consumer stops reading early.
func worker(ctx context.Context, id int, out chan<- int) {
	for i := 0; ; i++ {
		select {
		case out <- id*100 + i:
		case <-ctx.Done():
			return
		}
	}
