import (
	"fmt"
	"sync"
)

// config is written once, then published via the channel.
type config struct {
	version int
	name    string
}

func main() {
	// Publication via an unbuffered channel establishes happens-before:
	// the send happens-before the corresponding receive completes, so the
	// receiver is guaranteed to observe the fully initialized *config.
	ch := make(chan *config)

	go func() {
		c := &config{version: 2, name: "prod"}
		ch <- c // send happens-before the matching receive completes
	}()

	got := <-ch
	fmt.Println(got.version, got.name)

	// Mutex also establishes happens-before: the n-th Unlock
	// happens-before the (n+1)-th Lock that observes it.
	var mu sync.Mutex
	var counter int
	var wg sync.WaitGroup
	for i := 0; i < 100; i++ {
		wg.Add(1)
		go func() {
			defer wg.Done()
			mu.Lock()
			counter++
			mu.Unlock()
		}()
	}
	wg.Wait()
	fmt.Println(counter)
}
