import (
	"bytes"
	"fmt"
	"sync"
)

var bufPool = sync.Pool{
	New: func() any { return new(bytes.Buffer) },
}

func render(id int) string {
	b := bufPool.Get().(*bytes.Buffer)
	defer func() {
		b.Reset() // clear state before returning ownership
		bufPool.Put(b)
	}()
	fmt.Fprintf(b, "item-%d", id)
	return b.String() // copy out; never leak b
}

// counter is padded so concurrent updates from different Ps
// land on distinct 64-byte cache lines (no false sharing).
type counter struct {
	n uint64
	_ [56]byte
}

func main() {
	stats := make([]counter, 4)
	var wg sync.WaitGroup
	for p := range stats {
		wg.Add(1)
		go func(p int) {
			defer wg.Done()
			for i := 0; i < 1000; i++ {
				stats[p].n++
				_ = render(p*1000 + i)
			}
		}(p)
	}
	wg.Wait()
	var total uint64
	for i := range stats {
		total += stats[i].n
	}
	fmt.Println(total)
}
