  ('go-std-time', 'go', 'main.go', 'package main

import (
	"context"
	"fmt"
	"time"
)

// poll runs work every interval until ctx is cancelled.
func poll(ctx context.Context, interval time.Duration, work func(time.Duration)) {
	start := time.Now()
	ticker := time.NewTicker(interval)
	defer ticker.Stop() // stop future ticks promptly on return

	for {
		select {
		case <-ctx.Done():
			return
		case <-ticker.C:
			// Since uses the monotonic reading captured in start,
			// so it is immune to wall-clock jumps (NTP, DST, manual sets).
			work(time.Since(start))
		}
	}
}

func main() {
	ctx, cancel := context.WithTimeout(context.Background(), 120*time.Millisecond)
	defer cancel()

	ticks := 0
	poll(ctx, 40*time.Millisecond, func(elapsed time.Duration) {
		ticks++
		fmt.Printf("tick %d after ~%v\n", ticks, elapsed.Round(10*time.Millisecond))
	})

	// Round(0) strips the monotonic reading for stable marshaling/equality.
	t := time.Now().Round(0)
	fmt.Println("stripped monotonic:", t.Equal(t))
}
