import (
	"fmt"
	"unsafe"
)

// Bad ordering: bool, int64, bool -> padding bloats the struct.
type Bad struct {
	a bool
	b int64
	c bool
}

// Good ordering: largest-to-smallest packs fields tightly.
type Good struct {
	b int64
	a bool
	c bool
}

// Point is a small value type stored contiguously in a slice.
type Point struct {
	X, Y int32
}

func sumX(pts []Point) int64 {
	var total int64
	for i := range pts {
		total += int64(pts[i].X)
	}
	return total
}

func main() {
	fmt.Printf("Bad  size=%d align=%d\n", unsafe.Sizeof(Bad{}), unsafe.Alignof(Bad{}))
	fmt.Printf("Good size=%d align=%d\n", unsafe.Sizeof(Good{}), unsafe.Alignof(Good{}))

	pts := make([]Point, 0, 4)
	for i := int32(0); i < 4; i++ {
		pts = append(pts, Point{X: i, Y: i * i})
	}
	fmt.Println("sumX:", sumX(pts))

	// map keyed by a comparable struct: fast lookups, no allocation per key.
	seen := make(map[Point]bool, len(pts))
	for _, p := range pts {
		seen[p] = true
	}
	fmt.Println("distinct points:", len(seen))
}
