import (
	"fmt"
	"sort"
	"strings"
)

// normalize dedupes and sorts words case-insensitively.
func normalize(in []string) []string {
	seen := make(map[string]struct{})
	var out []string
	for _, w := range in {
		w = strings.ToLower(strings.TrimSpace(w))
		if w == "" {
			continue
		}
		if _, ok := seen[w]; ok {
			continue
		}
		seen[w] = struct{}{}
		out = append(out, w)
	}
	sort.Strings(out)
	return out
}

func main() {
	cases := []struct {
		name string
		in   []string
		want []string
	}{
		{name: "empty", in: nil, want: nil},
		{name: "dedup_and_sort", in: []string{"B", "a", "b"}, want: []string{"a", "b"}},
		{name: "trims_blanks", in: []string{" x ", "", "x"}, want: []string{"x"}},
	}
	for _, tc := range cases {
		got := normalize(tc.in)
		fmt.Printf("%s: %v (want %v)\n", tc.name, got, tc.want)
	}
}
