	// Validate: a complete chain must have at least one node with HP=1 (direct).
	direct := 0
	for _, n := range chain.Nodes {
		if n.HP == 1 {
			direct++
		}
	}
	fmt.Printf("\nchain complete=%d  nodes=%d  direct-relationships=%d\n",
		chain.Complete, len(chain.Nodes), direct)
}
