  ('prep-stacks-queues-find-moving-average-in-sliding::outcome', 'prep-stacks-queues-find-moving-average-in-sliding', 'When the run completes, what does the final step convey?', 'Return the average over the current window: sum  ÷  = . This is the result of Next().', 5),
  ('prep-stacks-queues-implement-queue-with-max::pattern', 'prep-stacks-queues-implement-queue-with-max', 'Which approach fits "Implement queue with max"?', 'A decreasing deque shadows the queue; its front is always the max', 0),
  ('prep-stacks-queues-implement-queue-with-max::key-step', 'prep-stacks-queues-implement-queue-with-max', 'On the "DEQ_POP" step (→ ), what happens?', ': remove and return the front value  from the FIFO queue.', 1),
